window.bibleReaderData = window.bibleReaderData || {chapters:{}};
window.bibleReaderData.chapters = window.bibleReaderData.chapters || {};
window.bibleReaderData.chapters['LUK'] = window.bibleReaderData.chapters['LUK'] || {};
(function(chapters){ for (const c in chapters){ window.bibleReaderData.chapters['LUK'][c]=window.bibleReaderData.chapters['LUK'][c]||{}; Object.assign(window.bibleReaderData.chapters['LUK'][c], chapters[c]); } })({"1":{"fa":[{"v":1,"t":"از آنجهت که بسیاری دست خود را درازکردند به سوی تالیف حکایت آن اموری که نزد ما به اتمام رسید،"},{"v":2,"t":"چنانچه آنانی که از ابتدانظارگان و خادمان کلام بودند به ما رسانیدند،"},{"v":3,"t":"من نیز مصلحت چنان دیدم که همه را من البدایه به تدقیق در‌پی رفته، به ترتیب به تو بنویسم‌ای تیوفلس عزیز،"},{"v":4,"t":"تا صحت آن کلامی که در آن تعلیم یافته‌ای دریابی."},{"v":5,"t":"در ایام هیرودیس پادشاه یهودیه، کاهنی زکریا نام از فرقه ابیا بود که زن او از دختران هارون بود و الیصابات نام داشت."},{"v":6,"t":"و هر دو در حضورخدا صالح و به جمیع احکام و فرایض خداوند، بی‌عیب سالک بودند."},{"v":7,"t":"و ایشان را فرزندی نبودزیرا که الیصابات نازاد بود و هر دو دیرینه سال بودند."},{"v":8,"t":"و واقع شد که چون به نوبت فرقه خود درحضور خدا کهانت می‌کرد،"},{"v":9,"t":"حسب عادت کهانت، نوبت او شد که به قدس خداوند درآمده، بخور بسوزاند."},{"v":10,"t":"و در وقت بخور، تمام جماعت قوم بیرون عبادت می‌کردند."},{"v":11,"t":"ناگاه فرشته خداوند به طرف راست مذبح بخور ایستاده، بر وی ظاهر گشت."},{"v":12,"t":"چون زکریااو را دید، در حیرت افتاده، ترس بر او مستولی شد."},{"v":13,"t":"فرشته بدو گفت: «ای زکریا ترسان مباش، زیرا که دعای تو مستجاب گردیده است وزوجه ات الیصابات برای تو پسری خواهد زاییدو او را یحیی خواهی نامید."},{"v":14,"t":"و تو را خوشی وشادی رخ خواهد نمود و بسیاری از ولادت اومسرور خواهند شد."},{"v":15,"t":"زیرا که در حضورخداوند بزرگ خواهد بود و شراب و مسکری نخواهد نوشید و از شکم مادر خود، پر ازروح‌القدس خواهد بود."},{"v":16,"t":"و بسیاری ازبنی‌اسرائیل را، به سوی خداوند خدای ایشان خواهد برگردانید."},{"v":17,"t":"و او به روح و قوت الیاس پیش روی وی خواهد خرامید، تا دلهای پدران رابه طرف پسران و نافرمانان را به حکمت عادلان بگرداند تا قومی مستعد برای خدا مهیا سازد.»"},{"v":18,"t":"زکریا به فرشته گفت: «این را چگونه بدانم وحال آنکه من پیر هستم و زوجه‌ام دیرینه سال است؟»"},{"v":19,"t":"فرشته در جواب وی گفت: «من جبرائیل هستم که در حضور خدا می‌ایستم وفرستاده شدم تا به تو سخن گویم و از این امور تورا مژده دهم."},{"v":20,"t":"و الحال تا این امور واقع نگردد، گنگ شده یارای حرف زدن نخواهی داشت، زیراسخن های مرا که در وقت خود به وقوع خواهدپیوست، باور نکردی.»"},{"v":21,"t":"و جماعت منتظر زکریامی بودند و از طول توقف او در قدس متعجب شدند."},{"v":22,"t":"اما چون بیرون آمده نتوانست با ایشان حرف زند، پس فهمیدند که در قدس رویایی دیده است، پس به سوی ایشان اشاره می‌کرد و ساکت ماند."},{"v":23,"t":"و چون ایام خدمت او به اتمام رسید، به خانه خود رفت."},{"v":24,"t":"و بعد از آن روزها، زن او الیصابات حامله شده، مدت پنج ماه خود را پنهان نمود و گفت:"},{"v":25,"t":"«به اینطور خداوند به من عمل نمود درروزهایی که مرا منظور داشت، تا ننگ مرا از نظرمردم بردارد.»"},{"v":26,"t":"و در ماه ششم جبرائیل فرشته از جانب خدا به بلدی از جلیل که ناصره نام داشت، فرستاده شد."},{"v":27,"t":"نزد باکره‌ای نامزد مردی مسمی به یوسف از خاندان داود و نام آن باکره مریم بود."},{"v":28,"t":"پس فرشته نزد او داخل شده، گفت: «سلام برتو‌ای نعمت رسیده، خداوند با توست و تو درمیان زنان مبارک هستی.»"},{"v":29,"t":"چون او را دید، ازسخن او مضطرب شده، متفکر شد که این چه نوع تحیت است."},{"v":30,"t":"فرشته بدو گفت: «ای مریم ترسان مباش زیرا که نزد خدا نعمت یافته‌ای."},{"v":31,"t":"واینک حامله شده، پسری خواهی زایید و او راعیسی خواهی نامید."},{"v":32,"t":"او بزرگ خواهد بود و به پسر حضرت اعلی، مسمی شود، و خداوند خداتخت پدرش داود را بدو عطا خواهد فرمود."},{"v":33,"t":"واو بر خاندان یعقوب تا به ابد پادشاهی خواهد کردو سلطنت او را نهایت نخواهد بود.»"},{"v":34,"t":"مریم به فرشته گفت: «این چگونه می‌شود وحال آنکه مردی را نشناخته‌ام؟»"},{"v":35,"t":"فرشته درجواب وی گفت: «روح‌القدس بر تو خواهد آمد وقوت حضرت اعلی بر تو سایه خواهد افکند، از آنجهت آن مولود مقدس، پسر خدا خوانده خواهد شد."},{"v":36,"t":"و اینک الیصابات از خویشان تونیز در‌پیری به پسری حامله شده و این ماه ششم است، مر او را که نازاد می‌خواندند."},{"v":37,"t":"زیرا نزدخدا هیچ امری محال نیست.»"},{"v":38,"t":"مریم گفت: «اینک کنیز خداوندم. مرا برحسب سخن تو واقع شود.» پس فرشته از نزد او رفت."},{"v":39,"t":"در آن روزها، مریم برخاست و به بلدی ازکوهستان یهودیه بشتاب رفت."},{"v":40,"t":"و به خانه زکریادرآمده، به الیصابات سلام کرد."},{"v":41,"t":"و چون الیصابات سلام مریم را شنید، بچه در رحم او به حرکت آمد و الیصابات به روح‌القدس پر شده،"},{"v":42,"t":"به آواز بلند صدا زده گفت: «تو در میان زنان مبارک هستی و مبارک است ثمره رحم تو."},{"v":43,"t":"و ازکجا این به من رسید که مادر خداوند من، به نزد من آید؟"},{"v":44,"t":"زیرا اینک چون آواز سلام تو گوش زدمن شد، بچه از خوشی در رحم من به حرکت آمد."},{"v":45,"t":"و خوشابحال او که ایمان آورد، زیرا که آنچه از جانب خداوند به وی گفته شد، به انجام خواهدرسید.»"},{"v":46,"t":"پس مریم گفت: «جان من خداوند راتمجید می‌کند،"},{"v":47,"t":"و روح من به رهاننده من خدابوجد آمد،"},{"v":48,"t":"زیرا بر‌حقارت کنیز خود نظرافکند. زیرا هان از کنون تمامی طبقات مراخوشحال خواهند خواند،"},{"v":49,"t":"زیرا آن قادر، به من کارهای عظیم کرده و نام او قدوس است،"},{"v":50,"t":"ورحمت او نسلا بعد نسل است. بر آنانی که از او می ترسند."},{"v":51,"t":"به بازوی خود، قدرت را ظاهرفرمود و متکبران را به خیال دل ایشان پراکنده ساخت."},{"v":52,"t":"جباران را از تختها به زیر افکند. وفروتنان را سرافراز گردانید."},{"v":53,"t":"گرسنگان را به چیزهای نیکو سیر فرمود و دولتمندان راتهیدست رد نمود."},{"v":54,"t":"بنده خود اسرائیل را یاری کرد، به یادگاری رحمانیت خویش،"},{"v":55,"t":"چنانکه به اجداد ما گفته بود، به ابراهیم و به ذریت او تاابدالاباد.»"},{"v":56,"t":"و مریم قریب به سه ماه نزد وی ماند. پس به خانه خود مراجعت کرد."},{"v":57,"t":"اما چون الیصابات را وقت وضع حمل رسید، پسری بزاد."},{"v":58,"t":"و همسایگان و خویشان اوچون شنیدند که خداوند رحمت عظیمی بر وی کرده، با او شادی کردند."},{"v":59,"t":"و واقع شد در روزهشتم چون برای ختنه طفل آمدند، که نام پدرش زکریا را بر او می‌نهادند."},{"v":60,"t":"اما مادرش ملتفت شده، گفت: «نی بلکه به یحیی نامیده می‌شود.»"},{"v":61,"t":"به وی گفتند: «از قبیله تو هیچ‌کس این اسم راندارد.»"},{"v":62,"t":"پس به پدرش اشاره کردند که «او را چه نام خواهی نهاد؟»"},{"v":63,"t":"او تخته‌ای خواسته بنوشت که «نام او یحیی است» و همه متعجب شدند."},{"v":64,"t":"در ساعت، دهان و زبان او باز گشته، به حمدخدا متکلم شد."},{"v":65,"t":"پس بر تمامی همسایگان ایشان، خوف مستولی گشت و جمیع این وقایع در همه کوهستان یهودیه شهرت یافت."},{"v":66,"t":"و هرکه شنید، در خاطر خود تفکر نموده، گفت: «این چه نوع طفل خواهد بود؟» و دست خداوند با وی می بود."},{"v":67,"t":"و پدرش زکریا از روح‌القدس پر شده نبوت نموده، گفت:"},{"v":68,"t":"«خداوند خدای اسرائیل متبارک باد، زیرا از قوم خود تفقد نموده، برای ایشان فدایی قرار داد."},{"v":69,"t":"و شاخ نجاتی برای مابرافراشت، در خانه بنده خود داود."},{"v":70,"t":"چنانچه به زبان مقدسین گفت که از بدو عالم انبیای اومی بودند،"},{"v":71,"t":"رهایی از دشمنان ما و از دست آنانی که از ما نفرت دارند،"},{"v":72,"t":"تا رحمت را برپدران ما به‌جا آرد و عهد مقدس خود را تذکرفرماید."},{"v":73,"t":"سوگندی که برای پدر ما ابراهیم یادکرد،"},{"v":74,"t":"که ما را فیض عطا فرماید، تا از دست دشمنان خود رهایی یافته، او را بی‌خوف عبادت کنیم."},{"v":75,"t":"در حضور او به قدوسیت و عدالت، درتمامی روزهای عمر خود."},{"v":76,"t":"و تو‌ای طفل نبی حضرت اعلی خوانده خواهی شد، زیرا پیش روی خداوند خواهی خرامید، تا طرق او را مهیاسازی،"},{"v":77,"t":"تا قوم او را معرفت نجات دهی، درآمرزش گناهان ایشان."},{"v":78,"t":"به احشای رحمت خدای ما که به آن سپیده از عالم اعلی از ما تفقدنمود،"},{"v":79,"t":"تا ساکنان در ظلمت و ظل موت را نوردهد. و پایهای ما را به طریق سلامتی هدایت نماید.»"},{"v":80,"t":"پس طفل نمو کرده، در روح قوی می‌گشت. و تا روز ظهور خود برای اسرائیل، دربیابان بسر می‌برد."}]},"2":{"fa":[{"v":1,"t":"و در آن ایام حکمی از اوغسطس قیصرصادر گشت که تمام ربع مسکون را اسم نویسی کنند."},{"v":2,"t":"و این اسم نویسی اول شد، هنگامی که کیرینیوس والی سوریه بود."},{"v":3,"t":"پس همه مردم هر یک به شهر خود برای اسم نویسی می‌رفتند."},{"v":4,"t":"و یوسف نیز از جلیل از بلده ناصره به یهودیه به شهر داود که بیت لحم نام داشت، رفت. زیرا که او از خاندان و آل داود بود."},{"v":5,"t":"تا نام او بامریم که نامزد او بود و نزدیک به زاییدن بود، ثبت گردد."},{"v":6,"t":"و وقتی که ایشان در آنجا بودند، هنگام وضع حمل او رسیده،"},{"v":7,"t":"پسر نخستین خود رازایید. و او را در قنداقه پیچیده، در آخورخوابانید. زیرا که برای ایشان در منزل جای نبود."},{"v":8,"t":"و در آن نواحی، شبانان در صحرا بسرمی بردند و در شب پاسبانی گله های خویش می‌کردند."},{"v":9,"t":"ناگاه فرشته خداوند بر ایشان ظاهرشد و کبریایی خداوند بر گرد ایشان تابید و بغایت ترسان گشتند."},{"v":10,"t":"فرشته ایشان را گفت: «مترسید، زیرا اینک بشارت خوشی عظیم به شما می‌دهم که برای جمیع قوم خواهد بود."},{"v":11,"t":"که امروز برای شما در شهر داود، نجات‌دهنده‌ای که مسیح خداوند باشد متولد شد."},{"v":12,"t":"و علامت برای شمااین است که طفلی در قنداقه پیچیده و در آخورخوابیده خواهید یافت.»"},{"v":13,"t":"در همان حال فوجی از لشکر آسمانی با فرشته حاضر شده، خدا راتسبیح‌کنان می‌گفتند:"},{"v":14,"t":"«خدا را در اعلی علیین جلال و بر زمین سلامتی و در میان مردم رضامندی باد.»"},{"v":15,"t":"و چون فرشتگان از نزد ایشان به آسمان رفتند، شبانان با یکدیگر گفتند: «الان به بیت لحم برویم و این چیزی را که واقع شده و خداوند آن را به ما اعلام نموده است ببینیم.»"},{"v":16,"t":"پس به شتاب رفته، مریم و یوسف و آن طفل رادر آخور خوابیده یافتند."},{"v":17,"t":"چون این را دیدند، آن سخنی را که درباره طفل بدیشان گفته شده بود، شهرت دادند."},{"v":18,"t":"و هر‌که می‌شنید از آنچه شبانان بدیشان گفتند، تعجب می‌نمود."},{"v":19,"t":"امامریم در دل خود متفکر شده، این همه سخنان رانگاه می‌داشت."},{"v":20,"t":"و شبانان خدا را تمجید وحمدکنان برگشتند، به‌سبب همه آن اموری که دیده و شنیده بودند چنانکه به ایشان گفته شده بود."},{"v":21,"t":"و چون روز هشتم، وقت ختنه طفل رسید، او را عیسی نام نهادند، چنانکه فرشته قبل از قرارگرفتن او در رحم، او را نامیده بود."},{"v":22,"t":"و چون ایام تطهیر ایشان برحسب شریعت موسی رسید، او رابه اورشلیم بردند تا به خداوند بگذرانند."},{"v":23,"t":"چنانکه در شریعت خداوند مکتوب است که هر ذکوری که رحم را گشاید، مقدس خداوندخوانده شود."},{"v":24,"t":"و تا قربانی گذرانند، چنانکه درشریعت خداوند مقرر است، یعنی جفت فاخته‌ای یا دو جوجه کبوتر."},{"v":25,"t":"و اینک شخصی شمعون نام در اورشلیم بود که مرد صالح و متقی و منتظر تسلی اسرائیل بود و روح‌القدس بر وی بود."},{"v":26,"t":"و از روح‌القدس بدو وحی رسیده بود که، تا مسیح خداوند را نبینی موت را نخواهی دید."},{"v":27,"t":"پس به راهنمایی روح، به هیکل درآمد وچون والدینش آن طفل یعنی عیسی را آوردند تا رسوم شریعت را بجهت او بعمل آورند،"},{"v":28,"t":"او رادر آغوش خود کشیده و خدا را متبارک خوانده، گفت:"},{"v":29,"t":"«الحال‌ای خداوند بنده خود را رخصت می‌دهی، به سلامتی برحسب کلام خود."},{"v":30,"t":"زیراکه چشمان من نجات تو را دیده است،"},{"v":31,"t":"که آن راپیش روی جمیع امت‌ها مهیا ساختی."},{"v":32,"t":"نوری که کشف حجاب برای امت‌ها کند و قوم تواسرائیل را جلال بود.»"},{"v":33,"t":"و یوسف و مادرش ازآنچه درباره او گفته شد، تعجب نمودند."},{"v":34,"t":"پس شمعون ایشان را برکت داده، به مادرش مریم گفت: «اینک این طفل قرار داده شد، برای افتادن وبرخاستن بسیاری از آل اسرائیل و برای آیتی که به خلاف آن خواهند گفت."},{"v":35,"t":"و در قلب تو نیزشمشیری فرو خواهد رفت، تا افکار قلوب بسیاری مکشوف شود.»"},{"v":36,"t":"و زنی نبیه بود، حنا نام، دختر فنوئیل ازسبط اشیر بسیار سالخورده، که از زمان بکارت هفت سال با شوهر بسر برده بود."},{"v":37,"t":"و قریب به هشتاد و چهار سال بود که او بیوه گشته ازهیکل جدا نمی شد، بلکه شبانه‌روز به روزه ومناجات در عبادت مشغول می‌بود."},{"v":38,"t":"او درهمان ساعت در‌آمده، خدا را شکر نمود ودرباره او به همه منتظرین نجات در اورشلیم، تکلم نمود."},{"v":39,"t":"و چون تمامی رسوم شریعت خداوند را به پایان برده بودند، به شهر خود ناصره جلیل مراجعت کردند."},{"v":40,"t":"و طفل نمو کرده، به روح قوی می‌گشت و از حکمت پر شده، فیض خدا بروی می‌بود."},{"v":41,"t":"و والدین او هر ساله بجهت عید فصح، به اورشلیم می‌رفتند."},{"v":42,"t":"و چون دوازده ساله شد، موافق رسم عید، به اورشلیم آمدند."},{"v":43,"t":"وچون روزها را تمام کرده مراجعت می‌نمودند، آن طفل یعنی عیسی، در اورشلیم توقف نمودو یوسف و مادرش نمی دانستند."},{"v":44,"t":"بلکه چون گمان می‌بردند که او در قافله است، سفریکروزه کردند و او را در میان خویشان وآشنایان خود می‌جستند."},{"v":45,"t":"و چون او را نیافتند، در طلب او به اورشلیم برگشتند."},{"v":46,"t":"و بعد ازسه روز، او را در هیکل یافتند که در میان معلمان نشسته، سخنان ایشان را می‌شنود و ازایشان سوال همی کرد."},{"v":47,"t":"و هر‌که سخن او رامی شنید، از فهم و جوابهای او متحیرمی گشت."},{"v":48,"t":"چون ایشان او را دیدند، مضطرب شدند. پس مادرش به وی گفت: «ای فرزند چرا با ماچنین کردی؟ اینک پدرت و من غمناک گشته تو را جستجو می‌کردیم.»"},{"v":49,"t":"او به ایشان گفت: «از بهر‌چه مرا طلب می‌کردید، مگرندانسته‌اید که باید من در امور پدر خود باشم؟»"},{"v":50,"t":"ولی آن سخنی را که بدیشان گفت، نفهمیدند."},{"v":51,"t":"پس با ایشان روانه شده، به ناصره آمد و مطیع ایشان می‌بود و مادر او تمامی این امور را درخاطر خود نگاه می‌داشت."},{"v":52,"t":"و عیسی درحکمت و قامت و رضامندی نزد خدا و مردم ترقی می‌کرد."}]},"3":{"fa":[{"v":1,"t":"و در سال پانزدهم از سلطنت طیباریوس قیصر، در وقتی که پنطیوس پیلاطس، والی یهودیه بود و هیرودیس، تیترارک جلیل وبرادرش فیلپس تیترارک ایطوریه تراخونیتس ولیسانیوس تیترارک آبلیه"},{"v":2,"t":"و حنا و قیافا روسای کهنه بودند، کلام خدا به یحیی ابن زکریا در بیابان نازل شده،"},{"v":3,"t":"به تمامی حوالی اردن آمده، به تعمیدتوبه بجهت آمرزش گناهان موعظه می‌کرد."},{"v":4,"t":"چنانچه مکتوب است در صحیفه کلمات اشعیای نبی که می‌گوید: «صدای ندا کننده‌ای دربیابان که راه خداوند را مهیا سازید و طرق او راراست نمایید."},{"v":5,"t":"هر وادی انباشته و هر کوه و تلی پست و هر کجی راست و هر راه ناهموار صاف خواهد شد"},{"v":6,"t":"و تمامی بشر نجات خدا را خواهنددید.»"},{"v":7,"t":"آنگاه به آن جماعتی که برای تعمید وی بیرون می‌آمدند، گفت: «ای افعی‌زادگان، که شمارا نشان داد که از غضب آینده بگریزید؟"},{"v":8,"t":"پس ثمرات مناسب توبه بیاورید و در خاطر خود این سخن را راه مدهید که ابراهیم پدر ماست، زیرا به شما می‌گویم خدا قادر است که از این سنگها، فرزندان برای ابراهیم برانگیزاند."},{"v":9,"t":"و الان نیز تیشه بر ریشه درختان نهاده شده است، پس هر درختی که میوه نیکو نیاورد، بریده و در آتش افکنده می‌شود.»"},{"v":10,"t":"پس مردم از وی سوال نموده گفتند: «چه کنیم؟»"},{"v":11,"t":"او در جواب ایشان گفت: «هر‌که دوجامه دارد، به آنکه ندارد بدهد. و هرکه خوراک دارد نیز چنین کند.»"},{"v":12,"t":"و باجگیران نیز برای تعمید آمده، بدو گفتند: «ای استاد چه کنیم؟»"},{"v":13,"t":"بدیشان گفت: «زیادتر از آنچه مقرر است، مگیرید.»"},{"v":14,"t":"سپاهیان نیز از او پرسیده، گفتند: «ماچه کنیم؟» به ایشان گفت: «بر کسی ظلم مکنید وبر هیچ‌کس افترا مزنید و به مواجب خود اکتفاکنید.»"},{"v":15,"t":"و هنگامی که قوم مترصد می‌بودند و همه در خاطر خود درباره یحیی تفکر می‌نمودندکه این مسیح است یا نه،"},{"v":16,"t":"یحیی به همه متوجه شده گفت: «من شما را به آب تعمیدمی دهم، لیکن شخصی تواناتر از من می‌آید که لیاقت آن ندارم که بند نعلین او را باز کنم. اوشما را به روح‌القدس و آتش تعمید خواهد داد."},{"v":17,"t":"او غربال خود را به‌دست خود دارد وخرمن خویش را پاک کرده، گندم را در انبارخود ذخیره خواهد نمود و کاه را در آتشی که خاموشی نمی پذیرد خواهد سوزانید.»"},{"v":18,"t":"وبه نصایح بسیار دیگر، قوم را بشارت می‌داد."},{"v":19,"t":"اما هیرودیس تیترارک چون به‌سبب هیرودیا، زن برادر او فیلپس و سایر بدیهایی که هیرودیس کرده بود از وی توبیخ یافت،"},{"v":20,"t":"این رانیز بر همه افزود که یحیی را در زندان حبس نمود."},{"v":21,"t":"اما چون تمامی قوم تعمید یافته بودند وعیسی هم تعمید گرفته دعا می‌کرد، آسمان شکافته شد"},{"v":22,"t":"و روح‌القدس به هیات جسمانی، مانند کبوتری بر او نازل شد. و آوازی از آسمان در‌رسید که تو پسر حبیب من هستی که به توخشنودم."},{"v":23,"t":"و خود عیسی وقتی که شروع کرد، قریب به سی ساله بود. و حسب گمان خلق، پسر یوسف ابن هالی"},{"v":24,"t":"ابن متات، بن لاوی، بن ملکی، بن ینا، بن یوسف،"},{"v":25,"t":"ابن متاتیا، بن آموس، بن ناحوم، بن حسلی، بن نجی،"},{"v":26,"t":"ابن مات، بن متاتیا، بن شمعی، بن یوسف، بن یهودا،"},{"v":27,"t":"ابن یوحنا، بن ریسا، بن زروبابل، بن سالتیئیل، بن نیری،"},{"v":28,"t":"ابن ملکی، بن ادی، بن قوسام، بن ایلمودام، بن عیر،"},{"v":29,"t":"ابن یوسی، بن ایلعاذر، بن یوریم، بن متات، بن لاوی،"},{"v":30,"t":"ابن شمعون، بن یهودا، بن یوسف، بن یونان، بن ایلیاقیم،"},{"v":31,"t":"ابن ملیا، بن مینان، بن متاتا بن ناتان، بن داود،"},{"v":32,"t":"ابن یسی، بن عوبید، بن بوعز، بن شلمون، بن نحشون،"},{"v":33,"t":"ابن عمیناداب، بن ارام، بن حصرون، بن فارص، بن یهودا،"},{"v":34,"t":"ابن یعقوب، بن اسحق، بن ابراهیم، بن تارح، بن ناحور،"},{"v":35,"t":"ابن سروج، بن رعور، بن فالج، بن عابر، بن صالح،"},{"v":36,"t":"ابن قینان، بن ارفکشاد، بن سام، بن نوح، بن لامک،"},{"v":37,"t":"ابن متوشالح، بن خنوخ، بن یارد، بن مهللئیل، بن قینان،"},{"v":38,"t":"ابن انوش، بن شیث، بن آدم، بن الله."}]},"4":{"fa":[{"v":1,"t":"اما عیسی پر از روح‌القدس بوده، از اردن مراجعت کرد و روح او را به بیابان برد."},{"v":2,"t":"ومدت چهل روز ابلیس او را تجربه می‌نمود و درآن ایام چیزی نخورد. چون تمام شد، آخر گرسنه گردید."},{"v":3,"t":"و ابلیس بدو گفت: «اگر پسر خدا هستی، این سنگ را بگو تا نان گردد.»"},{"v":4,"t":"عیسی در جواب وی گفت: «مکتوب است که انسان به نان فقط زیست نمی کند، بلکه به هر کلمه خدا.»"},{"v":5,"t":"پس ابلیس او رابه کوهی بلند برده، تمامی ممالک جهان را درلحظه‌ای بدو نشان داد."},{"v":6,"t":"و ابلیس بدو گفت: «جمیع این قدرت و حشمت آنها را به تو می‌دهم، زیرا که به من سپرده شده است و به هر‌که می‌خواهم می‌بخشم."},{"v":7,"t":"پس اگر تو پیش من سجده کنی، همه از آن تو خواهد شد.»"},{"v":8,"t":"عیسی در جواب او گفت: «ای شیطان، مکتوب است، خداوند خدای خود را پرستش کن و غیر او راعبادت منما.»"},{"v":9,"t":"پس او را به اورشلیم برده، برکنگره هیکل قرار داد و بدو گفت: «اگر پسر خداهستی، خود را از اینجا به زیر انداز."},{"v":10,"t":"زیرامکتوب است که فرشتگان خود را درباره تو حکم فرماید تا تو را محافظت کنند."},{"v":11,"t":"و تو را به‌دستهای خود بردارند، مبادا پایت به سنگی خورد.»"},{"v":12,"t":"عیسی در جواب وی گفت که «گفته شده است، خداوند خدای خود را تجربه مکن.»"},{"v":13,"t":"و چون ابلیس جمیع تجربه را به اتمام رسانید، تا مدتی از او جدا شد."},{"v":14,"t":"و عیسی به قوت روح، به جلیل برگشت وخبر او در تمامی آن نواحی شهرت یافت."},{"v":15,"t":"و اودر کنایس ایشان تعلیم می‌داد و همه او را تعظیم می‌کردند."},{"v":16,"t":"و به ناصره جایی که پرورش یافته بود، رسید و بحسب دستور خود در روز سبت به کنیسه درآمده، برای تلاوت برخاست."},{"v":17,"t":"آنگاه صحیفه اشعیا نبی را بدو دادند و چون کتاب راگشود، موضعی را یافت که مکتوب است"},{"v":18,"t":"«روح خداوند بر من است، زیرا که مرا مسح کرد تا فقیران را بشارت دهم و مرا فرستاد، تاشکسته دلان را شفا بخشم و اسیران را به رستگاری و کوران را به بینایی، موعظه کنم و تاکوبیدگان را، آزاد سازم،"},{"v":19,"t":"و از سال پسندیده خداوند موعظه کنم.»"},{"v":20,"t":"پس کتاب را به هم پیچیده، به خادم سپرد وبنشست و چشمان همه اهل کنیسه بر وی دوخته می‌بود."},{"v":21,"t":"آنگاه بدیشان شروع به گفتن کرد که «امروز این نوشته در گوشهای شما تمام شد.»"},{"v":22,"t":"و همه بر وی شهادت دادند و از سخنان فیض آمیزی که از دهانش صادر می‌شد، تعجب نموده، گفتند: «مگر این پسر یوسف نیست؟»"},{"v":23,"t":"بدیشان گفت: «هرآینه این مثل را به من خواهیدگفت، ای طبیب خود را شفا بده. آنچه شنیده‌ایم که در کفرناحوم از تو صادر شد، اینجا نیز در وطن خویش بنما.»"},{"v":24,"t":"و گفت: «هرآینه به شمامی گویم که هیچ نبی در وطن خویش مقبول نباشد."},{"v":25,"t":"و به تحقیق شما را می‌گویم که بسا بیوه‌زنان در اسرائیل بودند، در ایام الیاس، وقتی که آسمان مدت سه سال و شش ماه بسته ماند، چنانکه قحطی عظیم در تمامی زمین پدید آمد،"},{"v":26,"t":"و الیاس نزد هیچ کدام از ایشان فرستاده نشد، مگر نزد بیوه‌زنی در صرفه صیدون."},{"v":27,"t":"و بساابرصان در اسرائیل بودند، در ایام الیشع نبی واحدی از ایشان طاهر نگشت، جز نعمان سریانی.»"},{"v":28,"t":"پس تمام اهل کنیسه چون این سخنان راشنیدند، پر از خشم گشتند."},{"v":29,"t":"و برخاسته او را ازشهر بیرون کردند و بر قله کوهی که قریه ایشان برآن بنا شده بود بردند، تا او را به زیر افکنند."},{"v":30,"t":"ولی از میان ایشان گذشته، برفت."},{"v":31,"t":"و به کفرناحوم شهری از جلیل فرود شده، در روزهای سبت، ایشان را تعلیم می‌داد."},{"v":32,"t":"و ازتعلیم او در حیرت افتادند، زیرا که کلام او باقدرت می‌بود."},{"v":33,"t":"و در کنیسه مردی بود، که روح دیو خبیث داشت و به آواز بلند فریادکنان می‌گفت:"},{"v":34,"t":"«آه‌ای عیسی ناصری، ما را با تو چه‌کار است، آیا آمده‌ای تا ما را هلاک سازی؟ تو را می شناسم کیستی، ای قدوس خدا.»"},{"v":35,"t":"پس عیسی او را نهیب داده، فرمود: «خاموش باش و ازوی بیرون آی.» در ساعت دیو او را در میان انداخته، از او بیرون شد و هیچ آسیبی بدونرسانید."},{"v":36,"t":"پس حیرت بر همه ایشان مستولی گشت و یکدیگر را مخاطب ساخته، گفتند: «این چه سخن است که این شخص با قدرت و قوت، ارواح پلید را امر می‌کند و بیرون می‌آیند!»"},{"v":37,"t":"وشهرت او در هر موضعی از آن حوالی، پهن شد."},{"v":38,"t":"و از کنیسه برخاسته، به خانه شمعون درآمد. و مادر‌زن شمعون را تب شدیدی عارض شده بود، برای او از وی التماس کردند."},{"v":39,"t":"پس برسر وی آمده، تب را نهیب داده، تب از او زایل شد. در ساعت برخاسته، به خدمتگذاری ایشان مشغول شد."},{"v":40,"t":"و چون آفتاب غروب می‌کرد، همه آنانی که اشخاص مبتلا به انواع مرضها داشتند، ایشان را نزد وی آوردند و به هر یکی از ایشان دست گذارده، شفا داد."},{"v":41,"t":"و دیوها نیز از بسیاری بیرون می‌رفتند و صیحه زنان می‌گفتند که «تو مسیح پسرخدا هستی.» ولی ایشان را قدغن کرده، نگذاشت که حرف زنند، زیرا که دانستند او مسیح است."},{"v":42,"t":"و چون روز شد، روانه شده به مکانی ویران رفت و گروهی کثیر در جستجوی او آمده، نزدش رسیدند و او را باز می‌داشتند که از نزد ایشان نرود."},{"v":43,"t":"به ایشان گفت: «مرا لازم است که به شهرهای دیگر نیز به ملکوت خدا بشارت دهم، زیرا که برای همین کار فرستاده شده‌ام.»"},{"v":44,"t":"پس در کنایس جلیل موعظه می‌نمود."}]},"5":{"fa":[{"v":1,"t":"و هنگامی که گروهی بر وی ازدحام می نمودند تا کلام خدا را بشنوند، او به کناردریاچه جنیسارت ایستاده بود."},{"v":2,"t":"و دو زورق رادر کنار دریاچه ایستاده دید که صیادان از آنهابیرون آمده، دامهای خود را شست و شومی نمودند."},{"v":3,"t":"پس به یکی از آن دو زورق که مال شمعون بود سوار شده، از او درخواست نمود که از خشکی اندکی دور ببرد. پس در زورق نشسته، مردم را تعلیم می‌داد."},{"v":4,"t":"و چون از سخن‌گفتن فارغ شد، به شمعون گفت: «به میانه دریاچه بران و دامهای خود رابرای شکار بیندازید.»"},{"v":5,"t":"شمعون در جواب وی گفت: «ای استاد، تمام شب را رنج برده چیزی نگرفتیم، لیکن به حکم تو، دام را خواهیم انداخت.»"},{"v":6,"t":"و چون چنین کردند، مقداری کثیر ازماهی صید کردند، چنانکه نزدیک بود دام ایشان گسسته شود."},{"v":7,"t":"و به رفقای خود که در زورق دیگربودند اشاره کردند که آمده ایشان را امداد کنند. پس آمده هر دو زورق را پر کردند بقسمی که نزدیک بود غرق شوند."},{"v":8,"t":"شمعون پطرس چون این را بدید، بر پایهای عیسی افتاده، گفت: «ای خداوند از من دور شو زیرا مردی گناهکارم.»"},{"v":9,"t":"چونکه به‌سبب صیدماهی که کرده بودند، دهشت بر او و همه رفقای وی مستولی شده بود."},{"v":10,"t":"و هم چنین نیز بریعقوب و یوحنا پسران زبدی که شریک شمعون بودند. عیسی به شمعون گفت: «مترس. پس از این مردم را صید خواهی کرد.»"},{"v":11,"t":"پس چون زورقهارا به کنار آوردند همه را ترک کرده، از عقب اوروانه شدند."},{"v":12,"t":"و چون او در شهری از شهرها بود ناگاه مردی پر از برص آمده، چون عیسی را بدید، به روی در‌افتاد و از او درخواست کرده، گفت: «خداوندا، اگر خواهی می‌توانی مرا طاهرسازی.»"},{"v":13,"t":"پس او دست آورده، وی را لمس نمود و گفت: «می‌خواهم. طاهر شو.» که فور برص از او زایل شد."},{"v":14,"t":"و او را قدغن کرد که «هیچ‌کس را خبر مده، بلکه رفته خود را به کاهن بنما و هدیه‌ای بجهت طهارت خود، بطوری که موسی فرموده است، بگذران تا بجهت ایشان شهادتی شود.»"},{"v":15,"t":"لیکن خبر او بیشتر شهرت یافت و گروهی بسیار جمع شدند تا کلام او رابشنوند و از مرضهای خود شفا یابند،"},{"v":16,"t":"و او به ویرانه‌ها عزلت جسته، به عبادت مشغول شد."},{"v":17,"t":"روزی از روزها واقع شد که او تعلیم می‌دادو فریسیان و فقها که از همه بلدان جلیل و یهودیه و اورشلیم آمده، نشسته بودند وقوت خداوندبرای شفای ایشان صادر می‌شد،"},{"v":18,"t":"که ناگاه چندنفر شخصی مفلوج را بر بستری آوردند ومی خواستند او را داخل کنند تا پیش روی وی بگذارند."},{"v":19,"t":"و چون به‌سبب انبوهی مردم راهی نیافتند که او را به خانه درآورند بر پشت بام رفته، او را با تختش از میان سفالها در وسط پیش عیسی گذاردند."},{"v":20,"t":"چون او ایمان ایشان را دید، به وی گفت: «ای مرد، گناهان تو آمرزیده شد.»"},{"v":21,"t":"آنگاه کاتبان و فریسیان در خاطر خود تفکرنموده، گفتن گرفتند: «این کیست که کفر می‌گوید. جز خدا و بس کیست که بتواند گناهان رابیامرزد؟»"},{"v":22,"t":"عیسی افکار ایشان را درک نموده، در جواب ایشان گفت: «چرا در خاطر خود تفکرمی کنید؟"},{"v":23,"t":"کدام سهلتر است، گفتن اینکه گناهان تو آمرزیده شد، یا گفتن اینکه برخیز و بخرام؟"},{"v":24,"t":"لیکن تا بدانید که پسر انسان را استطاعت آمرزیدن گناهان بر روی زمین هست، مفلوج راگفت، تو را می‌گویم برخیز و بستر خود رابرداشته، به خانه خود برو.»"},{"v":25,"t":"در ساعت برخاسته، پیش ایشان آنچه بر آن خوابیده بودبرداشت و به خانه خود خدا را حمدکنان روانه شد."},{"v":26,"t":"و حیرت همه را فرو گرفت و خدا راتمجید می‌نمودند و خوف بر ایشان مستولی شده، گفتند: «امروز چیزهای عجیب دیدیم.»"},{"v":27,"t":"از آن پس بیرون رفته، باجگیری را که لاوی نام داشت، بر باجگاه نشسته دید. او را گفت: «از عقب من بیا.»"},{"v":28,"t":"در حال همه‌چیز را ترک کرده، برخاست و در عقب وی روانه شد."},{"v":29,"t":"و لاوی ضیافتی بزرگ در خانه خود برای او کرد و جمعی بسیار از باجگیران و دیگران با ایشان نشستند."},{"v":30,"t":"اما کاتبان ایشان و فریسیان همهمه نموده، به شاگردان او گفتند: «برای چه با باجگیران وگناهکاران اکل و شرب می‌کنید؟»"},{"v":31,"t":"عیسی درجواب ایشان گفت: «تندرستان احتیاج به طبیب ندارند بلکه مریضان."},{"v":32,"t":"و نیامده‌ام تا عادلان بلکه تا عاصیان را به توبه بخوانم.»"},{"v":33,"t":"پس به وی گفتند: «از چه سبب شاگردان یحیی روزه بسیار می‌دارند و نماز می‌خوانند وهمچنین شاگردان فریسیان نیز، لیکن شاگردان تواکل و شرب می‌کنند.»"},{"v":34,"t":"بدیشان گفت: «آیامی توانید پسران خانه عروسی را مادامی که دامادبا ایشان است روزه‌دار سازید؟"},{"v":35,"t":"بلکه ایامی می‌آید که داماد از ایشان گرفته شود، آنگاه در آن روزها روزه خواهند داشت.»"},{"v":36,"t":"و مثلی برای ایشان آورد که «هیچ‌کس پارچه‌ای از جامه نو را بر جامه کهنه وصله نمی کند والا آن نو را پاره کند و وصله‌ای که از نوگرفته شد نیز در خور آن کهنه نبود."},{"v":37,"t":"و هیچ‌کس شراب نو را در مشکهای کهنه نمی ریزد والاشراب نو، مشکها را پاره می‌کند و خودش ریخته و مشکها تباه می‌گردد."},{"v":38,"t":"بلکه شراب نو را درمشکهای نو باید ریخت تا هر دو محفوظ بماند."},{"v":39,"t":"و کسی نیست که چون شراب کهنه را نوشیده فی الفور نو را طلب کند، زیرا می‌گوید کهنه بهتراست.»"}]},"6":{"fa":[{"v":1,"t":"و واقع شد در سبت دوم اولین که او از میان کشت زارها می‌گذشت و شاگردانش خوشه‌ها می‌چیدند و به کف مالیده می‌خوردند."},{"v":2,"t":"و بعضی از فریسیان بدیشان گفتند: «چرا کاری می‌کنید که کردن آن در سبت جایز نیست.»"},{"v":3,"t":"عیسی در جواب ایشان گفت: «آیا نخوانده ایدآنچه داود و رفقایش کردند در وقتی که گرسنه بودند،"},{"v":4,"t":"که چگونه به خانه خدا درآمده نان تقدمه را گرفته بخورد و به رفقای خود نیز داد که خوردن آن جز به کهنه روا نیست.»"},{"v":5,"t":"پس بدیشان گفت: «پسر انسان مالک روز سبت نیز هست.»"},{"v":6,"t":"و در سبت دیگر به کنیسه درآمده تعلیم می‌داد و در آنجا مردی بود که دست راستش خشک بود."},{"v":7,"t":"و کاتبان و فریسیان چشم بر اومی داشتند که شاید در سبت شفا دهد تا شکایتی بر او یابند."},{"v":8,"t":"او خیالات ایشان را درک نموده، بدان مرد دست خشک گفت: «برخیز و در میان بایست.» در حال برخاسته بایستاد."},{"v":9,"t":"عیسی بدیشان گفت: «از شما چیزی می‌پرسم که در روزسبت کدام رواست، نیکویی‌کردن یا بدی، رهانیدن جان یا هلاک کردن؟»"},{"v":10,"t":"پس چشم خود را بر جمیع ایشان گردانیده، بدو گفت: «دست خود را دراز کن.» او چنان کرد و فور دستش مثل دست دیگر صحیح گشت."},{"v":11,"t":"اما ایشان ازحماقت پر گشته به یکدیگر می‌گفتند که «باعیسی چه کنیم؟»"},{"v":12,"t":"و در آن روزها برفراز کوه برآمد تا عبادت کند وآن شب را در عبادت خدا به صبح آورد."},{"v":13,"t":"و چون روز شد، شاگردان خود را پیش طلبیده دوازده نفر از ایشان را انتخاب کرده، ایشان را نیزرسول خواند."},{"v":14,"t":"یعنی شمعون که او را پطرس نیز نام نهاد و برادرش اندریاس، یعقوب و یوحنا، فیلپس و برتولما،"},{"v":15,"t":"متی و توما، یعقوب ابن حلفی و شمعون معروف به غیور."},{"v":16,"t":"یهودا برادریعقوب و یهودای اسخریوطی که تسلیم‌کننده وی بود."},{"v":17,"t":"و با ایشان به زیر آمده، بر جای همواربایستاد. و جمعی از شاگردان وی و گروهی بسیاراز قوم، از تمام یهودیه و اورشلیم و کناره دریای صور و صیدون آمدند تا کلام او را بشنوند و ازامراض خود شفا یابند."},{"v":18,"t":"و کسانی که از ارواح پلید معذب بودند، شفا یافتند."},{"v":19,"t":"و تمام آن گروه می‌خواستند او را لمس کنند. زیرا قوتی از وی صادر شده، همه را صحت می‌بخشید."},{"v":20,"t":"پس نظر خود را به شاگردان خویش افکنده، گفت: «خوشابحال شما‌ای مساکین زیراملکوت خدا از آن شما است."},{"v":21,"t":"خوشابحال شماکه اکنون گرسنه‌اید، زیرا که سیر خواهید شد. خوشابحال شما که الحال گریانید، زیرا خواهیدخندید."},{"v":22,"t":"خوشابحال شما وقتی که مردم بخاطرپسر انسان از شما نفرت گیرند و شما را از خودجدا سازند و دشنام دهند و نام شما را مثل شریربیرون کنند."},{"v":23,"t":"در آن روز شاد باشید و وجدنمایید زیرا اینک اجر شما در آسمان عظیم می‌باشد، زیرا که به همینطور پدران ایشان با انبیاسلوک نمودند."},{"v":24,"t":"«لیکن وای بر شما‌ای دولتمندان زیرا که تسلی خود را یافته‌اید."},{"v":25,"t":"وای بر شما‌ای سیرشدگان، زیرا گرسنه خواهید شد. وای بر شماکه الان خندانید زیرا که ماتم و گریه خواهید کرد."},{"v":26,"t":"وای بر شما وقتی که جمیع مردم شما راتحسین کنند، زیرا همچنین پدران ایشان با انبیای کذبه کردند."},{"v":27,"t":"«لیکن‌ای شنوندگان شما را می‌گویم دشمنان خود را دوست دارید و با کسانی که ازشما نفرت کنند، احسان کنید."},{"v":28,"t":"و هر‌که شما رالعن کند، برای او برکت بطلبید و برای هرکه با شماکینه دارد، دعای خیر کنید."},{"v":29,"t":"و هرکه بر رخسارتو زند، دیگری را نیز به سوی او بگردان و کسی‌که ردای تو را بگیرد، قبا را نیز از او مضایقه مکن."},{"v":30,"t":"هرکه از تو سوال کند بدو بده و هر‌که مال تو راگیرد از وی باز مخواه."},{"v":31,"t":"و چنانکه می‌خواهیدمردم با شما عمل کنند، شما نیز به همانطور باایشان سلوک نمایید."},{"v":32,"t":"«زیرا اگر محبان خود را محبت نمایید، شما را چه فضیلت است؟ زیرا گناهکاران هم محبان خود را محبت می‌نمایند."},{"v":33,"t":"و اگر احسان کنید با هر‌که به شما احسان کند، چه فضیلت دارید؟ چونکه گناهکاران نیز چنین می‌کنند."},{"v":34,"t":"واگر قرض دهید به آنانی که امید بازگرفتن از ایشان دارید، شما را چه فضیلت است؟ زیرا گناهکاران نیز به گناهکاران قرض می‌دهند تا از ایشان عوض گیرند."},{"v":35,"t":"بلکه دشمنان خود را محبت نمایید واحسان کنید و بدون امید عوض، قرض دهید زیراکه اجر شما عظیم خواهد بود و پسران حضرت اعلی خواهید بود چونکه او با ناسپاسان وبدکاران مهربان است."},{"v":36,"t":"پس رحیم باشید چنانکه پدر شما نیز رحیم است."},{"v":37,"t":"«داوری مکنید تا بر شما داوری نشود وحکم مکنید تا بر شما حکم نشود و عفو کنید تاآمرزیده شوید."},{"v":38,"t":"بدهید تا به شما داده شود. زیرا پیمانه نیکوی افشرده و جنبانیده و لبریز شده را در دامن شما خواهند گذارد. زیرا که به همان پیمانه‌ای که می‌پیمایید برای شما پیموده خواهدشد.»"},{"v":39,"t":"پس برای ایشان مثلی زد که «آیا می‌تواند کور، کور را راهنمایی کند؟ آیا هر دو در حفره‌ای نمی افتند؟"},{"v":40,"t":"شاگرد از معلم خویش بهتر نیست لیکن هر‌که کامل شده باشد، مثل استاد خود بود."},{"v":41,"t":"و چرا خسی را که در چشم برادر تو است می‌بینی و چوبی را که در چشم خود داری نمی یابی؟"},{"v":42,"t":"و چگونه بتوانی برادر خود را گویی‌ای برادر اجازت ده تا خس را از چشم تو برآورم و چوبی را که در چشم خود داری نمی بینی. ای ریاکار اول چوب را از چشم خود بیرون کن، آنگاه نیکو خواهی دید تا خس را از چشم برادر خودبرآوری."},{"v":43,"t":"«زیرا هیچ درخت نیکو میوه بد بارنمی آورد و نه درخت بد، میوه نیکو آورد."},{"v":44,"t":"زیراکه هر درخت از میوه‌اش شناخته می‌شود از خارانجیر را نمی یابند و از بوته، انگور را نمی چینند."},{"v":45,"t":"آدم نیکو از خزینه خوب دل خود چیز نیکوبرمی آورد و شخص شریر از خزینه بد دل خویش چیز بد بیرون می‌آورد. زیرا که از زیادتی دل زبان سخن می‌گوید."},{"v":46,"t":"«و چون است که مرا خداوندا خداوندامی گویید و آنچه می‌گویم بعمل نمی آورید."},{"v":47,"t":"هر‌که نزد من آید و سخنان مرا شنود و آنها را به‌جا آورد، شما را نشان می‌دهم که به چه کس مشابهت دارد."},{"v":48,"t":"مثل شخصی است که خانه‌ای می‌ساخت و زمین را کنده گود نمود و بنیادش رابر سنگ نهاد. پس چون سیلاب آمده، سیل بر آن خانه زور آورد، نتوانست آن را جنبش دهد زیراکه بر سنگ بنا شده بود."},{"v":49,"t":"لیکن هر‌که شنید وعمل نیاورد مانند شخصی است که خانه‌ای برروی زمین بی‌بنیاد بنا کرد که چون سیل بر آن صدمه زد، فور افتاد و خرابی آن خانه عظیم بود.»"}]},"7":{"fa":[{"v":1,"t":"و چون همه سخنان خود را به سمع خلق به اتمام رسانید، وارد کفرناحوم شد."},{"v":2,"t":"ویوزباشی را غلامی که عزیز او بود مریض ومشرف بر موت بود."},{"v":3,"t":"چون خبر عیسی را شنید، مشایخ یهود را نزد وی فرستاده از او خواهش کرد که آمده غلام او را شفا بخشد."},{"v":4,"t":"ایشان نزدعیسی آمده به الحاح نزد او التماس کرده گفتند: «مستحق است که این احسان را برایش به‌جاآوری."},{"v":5,"t":"زیرا قوم ما را دوست می‌دارد و خودبرای ما کنیسه را ساخت.»"},{"v":6,"t":"پس عیسی با ایشان روانه شد و چون نزدیک به خانه رسید، یوزباشی چند نفر از دوستان خودرا نزد او فرستاده بدو گفت: «خداوندا زحمت مکش زیرا لایق آن نیستم که زیر سقف من درآیی."},{"v":7,"t":"و از این سبب خود را لایق آن ندانستم که نزد تو آیم، بلکه سخنی بگو تا بنده من صحیح شود."},{"v":8,"t":"زیرا که من نیز شخصی هستم زیر حکم ولشکریان زیر دست خود دارم. چون به یکی گویم برو، می‌رود و به دیگری بیا، می‌آید و به غلام خود این را بکن، می‌کند.»"},{"v":9,"t":"چون عیسی این راشنید، تعجب نموده به سوی آن جماعتی که از عقب او می‌آمدند روی گردانیده، گفت: «به شمامی گویم چنین ایمانی، در اسرائیل هم نیافته‌ام.»"},{"v":10,"t":"پس فرستادگان به خانه برگشته، آن غلام بیماررا صحیح یافتند."},{"v":11,"t":"و دو روز بعد به شهری مسمی به نائین می‌رفت و بسیاری از شاگردان او و گروهی عظیم، همراهش می‌رفتند."},{"v":12,"t":"چون نزدیک به دروازه شهر رسید، ناگاه میتی را که پسر یگانه بیوه‌زنی بود می‌بردند و انبوهی کثیر از اهل شهر، با وی می‌آمدند."},{"v":13,"t":"چون خداوند او را دید، دلش بر اوبسوخت و به وی گفت: «گریان مباش.»"},{"v":14,"t":"و نزدیک آمده تابوت را لمس نمود وحاملان آن بایستادند. پس گفت: «ای جوان تو رامی گویم برخیز.»"},{"v":15,"t":"در ساعت آن مرده راست بنشست و سخن‌گفتن آغاز کرد و او را به مادرش سپرد."},{"v":16,"t":"پس خوف همه را فراگرفت و خدا راتمجیدکنان می‌گفتند که «نبی‌ای بزرگ در میان مامبعوث شده و خدا از قوم خود تفقد نموده است.»"},{"v":17,"t":"پس این خبر درباره او در تمام یهودیه و جمیع آن مرز و بوم منتشر شد."},{"v":18,"t":"و شاگردان یحیی او را از جمیع این وقایع مطلع ساختند."},{"v":19,"t":"پس یحیی دو نفر از شاگردان خود را طلبیده، نزد عیسی فرستاده، عرض نمودکه «آیا تو آن آینده هستی یا منتظر دیگری باشیم؟»"},{"v":20,"t":"آن دو نفر نزد وی آمده، گفتند: «یحیی تعمید‌دهنده ما را نزد تو فرستاده، می‌گوید آیا تو آن آینده هستی یا منتظر دیگری باشیم.»"},{"v":21,"t":"در همان ساعت، بسیاری را از مرضهاو بلایا و ارواح پلید شفا داد و کوران بسیاری رابینایی بخشید."},{"v":22,"t":"عیسی در جواب ایشان گفت: «بروید و یحیی را از آنچه دیده و شنیده‌اید خبردهید که کوران، بینا و لنگان خرامان و ابرصان طاهر و کران، شنوا و مردگان، زنده می‌گردند و به فقرا بشارت داده می‌شود."},{"v":23,"t":"و خوشابحال کسی‌که در من لغزش نخورد.»"},{"v":24,"t":"و چون فرستادگان یحیی رفته بودند، درباره یحیی بدان جماعت آغاز سخن نهاد که «برای دیدن چه چیز به صحرا بیرون رفته بودید، آیا نی را که از باد در جنبش است؟"},{"v":25,"t":"بلکه بجهت دیدن چه بیرون رفتید، آیا کسی را که به لباس نرم ملبس باشد؟ اینک آنانی که لباس فاخر می‌پوشندو عیاشی می‌کنند، در قصرهای سلاطین هستند."},{"v":26,"t":"پس برای دیدن چه رفته بودید، آیا نبی‌ای را؟ بلی به شما می‌گویم کسی را که از نبی هم بزرگتراست."},{"v":27,"t":"زیرا این است آنکه درباره وی مکتوب است، اینک من رسول خود را پیش روی تومی فرستم تا راه تو را پیش تو مهیا سازد."},{"v":28,"t":"زیراکه شما را می‌گویم از اولاد زنان نبی‌ای بزرگتر ازیحیی تعمید‌دهنده نیست، لیکن آنکه در ملکوت خدا کوچکتر است از وی بزرگتر است.»"},{"v":29,"t":"وتمام قوم و باجگیران چون شنیدند، خدا راتمجید کردند زیرا که تعمید از یحیی یافته بودند."},{"v":30,"t":"لیکن فریسیان و فقها اراده خدا را از خود ردنمودند زیرا که از وی تعمید نیافته بودند."},{"v":31,"t":"آنگاه خداوند گفت: «مردمان این طبقه را به چه تشبیه کنم و مانند چه می‌باشند؟"},{"v":32,"t":"اطفالی را می مانند که در بازارها نشسته، یکدیگر را صدازده می‌گویند، برای شما نواختیم رقص نکردید ونوحه گری کردیم گریه ننمودید."},{"v":33,"t":"زیرا که یحیی تعمید‌دهنده آمد که نه نان می‌خورد و نه شراب می‌آشامید، می‌گویید دیو دارد."},{"v":34,"t":"پسر انسان آمد که می‌خورد و می‌آشامد، می‌گویید اینک مردی است پرخور و باده پرست و دوست باجگیران و گناهکاران."},{"v":35,"t":"اما حکمت از جمیع فرزندان خود مصدق می‌شود."},{"v":36,"t":"و یکی از فریسیان از او وعده خواست که بااو غذا خورد پس به خانه فریسی درآمده بنشست."},{"v":37,"t":"که ناگاه زنی که در آن شهر گناهکاربود، چون شنید که در خانه فریسی به غذا نشسته است شیشه‌ای از عطر آورده،"},{"v":38,"t":"در پشت سر اونزد پایهایش گریان بایستاد و شروع کرد به شستن پایهای او به اشک خود و خشکانیدن آنها به موی سر خود و پایهای وی را بوسیده آنها را به عطرتدهین کرد."},{"v":39,"t":"چون فریسی‌ای که از او وعده خواسته بوداین را بدید، با خود می‌گفت که «این شخص اگرنبی بودی هرآینه دانستی که این کدام و چگونه زن است که او را لمس می‌کند، زیرا گناهکاری است.»"},{"v":40,"t":"عیسی جواب داده به وی گفت: «ای شمعون چیزی دارم که به تو گویم.» گفت: «ای استاد بگو.»"},{"v":41,"t":"گفت: «طلبکاری را دو بدهکار بودکه از یکی پانصد و از دیگری پنجاه دینار طلب داشتی."},{"v":42,"t":"چون چیزی نداشتند که ادا کنند، هر دو را بخشید. بگو کدام‌یک از آن دو او را زیادترمحبت خواهد نمود.»"},{"v":43,"t":"شمعون در جواب گفت: «گمان می‌کنم آنکه او را زیادتر بخشید.» به وی گفت: «نیکو گفتی.»"},{"v":44,"t":"پس به سوی آن زن اشاره نموده به شمعون گفت: «این زن را نمی بینی، به خانه تو آمدم آب بجهت پایهای من نیاوردی، ولی این زن پایهای مرا به اشکها شست و به مویهای سر خود آنها راخشک کرد."},{"v":45,"t":"مرا نبوسیدی، لیکن این زن ازوقتی که داخل شدم از بوسیدن پایهای من بازنایستاد."},{"v":46,"t":"سر مرا به روغن مسح نکردی، لیکن اوپایهای مرا به عطر تدهین کرد."},{"v":47,"t":"از این جهت به تو می‌گویم، گناهان او که بسیار است آمرزیده شد، زیرا که محبت بسیار نموده است. لیکن آنکه آمرزش کمتر یافت، محبت کمتر می‌نماید.»"},{"v":48,"t":"پس به آن زن گفت: «گناهان تو آمرزیده شد.»"},{"v":49,"t":"و اهل مجلس در خاطر خود تفکر آغاز کردندکه این کیست که گناهان را هم می‌آمرزد."},{"v":50,"t":"پس به آن زن گفت: «ایمانت تو را نجات داده است به سلامتی روانه شو.»"}]},"8":{"fa":[{"v":1,"t":"و بعد از آن واقع شد که او در هر شهری ودهی گشته، موعظه می‌نمود و به ملکوت خدا بشارت می‌داد و آن دوازده با وی می‌بودند."},{"v":2,"t":"و زنان چند که از ارواح پلید و مرضها شفا یافته بودند، یعنی مریم معروف به مجدلیه که از اوهفت دیو بیرون رفته بودند،"},{"v":3,"t":"و یونا زوجه خوزا، ناظر هیرودیس و سوسن و بسیاری از زنان دیگرکه از اموال خود او را خدمت می‌کردند."},{"v":4,"t":"و چون گروهی بسیار فراهم می‌شدند و از هرشهر نزد او می‌آمدند مثلی آورده، گفت"},{"v":5,"t":"که «برزگری بجهت تخم کاشتن بیرون رفت. و وقتی که تخم می‌کاشت بعضی بر کناره راه ریخته شد وپایمال شده، مرغان هوا آن را خوردند."},{"v":6,"t":"وپاره‌ای بر سنگلاخ افتاده چون رویید از آنجهت که رطوبتی نداشت خشک گردید."},{"v":7,"t":"و قدری درمیان خارها افکنده شد که خارها با آن نمو کرده آن را خفه نمود."},{"v":8,"t":"و بعضی در زمین نیکو پاشیده شده رویید و صد چندان ثمر آورد.» چون این بگفت ندا در‌داد «هر‌که گوش شنوا دارد بشنود.»"},{"v":9,"t":"پس شاگردانش از او سوال نموده، گفتند که «معنی‌این مثل چیست؟»"},{"v":10,"t":"گفت: «شما رادانستن اسرار ملکوت خدا عطا شده است و لیکن دیگران را به واسطه مثلها، تا نگریسته نبینند وشنیده درک نکنند."},{"v":11,"t":"اما مثل این است که تخم کلام خداست."},{"v":12,"t":"و آنانی که در کنار راه هستندکسانی می‌باشند که چون می‌شنوند، فور ابلیس آمده کلام را از دلهای ایشان می‌رباید، مبادا ایمان آورده نجات یابند."},{"v":13,"t":"و آنانی که بر سنگلاخ هستند کسانی می‌باشند که چون کلام رامی شنوند آن را به شادی می‌پذیرند و اینها ریشه ندارند پس تا مدتی ایمان می‌دارند و در وقت آزمایش، مرتد می‌شوند."},{"v":14,"t":"اما آنچه در خارهاافتاد اشخاصی می‌باشند که چون شنوند می‌روند و اندیشه های روزگار و دولت و لذات آن ایشان راخفه می‌کند و هیچ میوه به‌کمال نمی رسانند."},{"v":15,"t":"اما آنچه در زمین نیکو واقع گشت کسانی می‌باشند که کلام را به دل راست و نیکو شنیده، آن را نگاه می‌دارند و با صبر، ثمر می‌آورند."},{"v":16,"t":"«و هیچ‌کس چراغ را افروخته، آن را زیرظرفی یا تختی پنهان نمی کند بلکه بر چراغدان می‌گذارد تا هر‌که داخل شود روشنی را ببیند."},{"v":17,"t":"زیرا چیزی نهان نیست که ظاهر نگردد و نه مستور که معلوم و هویدا نشود."},{"v":18,"t":"پس احتیاطنمایید که به چه طور می‌شنوید، زیرا هر‌که داردبدو داده خواهد شد و از آنکه ندارد آنچه گمان هم می‌برد که دارد، از او گرفته خواهد شد.»"},{"v":19,"t":"و مادر وبرادران او نزد وی آمده به‌سبب ازدحام خلق نتوانستند او را ملاقات کنند."},{"v":20,"t":"پس او را خبر داده گفتند: «مادر و برادرانت بیرون ایستاده می‌خواهند تو را ببینند.»"},{"v":21,"t":"در جواب ایشان گفت: «مادر و برادران من اینانند که کلام خدا را شنیده آن را به‌جا می‌آورند.»"},{"v":22,"t":"روزی از روزها او با شاگردان خود به کشتی سوار شده، به ایشان گفت: «به سوی آن کناردریاچه عبور بکنیم.» پس کشتی را حرکت دادند."},{"v":23,"t":"و چون می‌رفتند، خواب او را در ربود که ناگاه طوفان باد بر دریاچه فرود آمد، بحدی که کشتی از آب پر می‌شد و ایشان در خطر افتادند."},{"v":24,"t":"پس نزد او آمده او را بیدار کرده، گفتند: «استادا، استادا، هلاک می‌شویم.» پس برخاسته باد وتلاطم آب را نهیب داد تا ساکن گشت و آرامی پدید آمد."},{"v":25,"t":"پس به ایشان گفت: «ایمان شما کجااست؟» ایشان ترسان و متعجب شده با یکدیگرمی گفتند که «این چطور آدمی است که بادها وآب را هم امر می‌فرماید و اطاعت او می‌کنند.»"},{"v":26,"t":"و به زمین جدریان که مقابل جلیل است، رسیدند."},{"v":27,"t":"چون به خشکی فرود آمد، ناگاه شخصی از آن شهر‌که از مدت مدیدی دیوهاداشتی و رخت نپوشیدی و در خانه نماندی بلکه در قبرها منزل داشتی دچار وی گردید."},{"v":28,"t":"چون عیسی را دید، نعره زد و پیش او افتاده به آواز بلندگفت: «ای عیسی پسر خدای تعالی، مرا با تو چه‌کار است؟ از تو التماس دارم که مرا عذاب ندهی.»"},{"v":29,"t":"زیرا که روح خبیث را امر فرموده بودکه از آن شخص بیرون آید. چونکه بارها او راگرفته بود، چنانکه هر‌چند او را به زنجیرها وکنده‌ها بسته نگاه می‌داشتند، بندها را می‌گسیخت و دیو او را به صحرا می‌راند."},{"v":30,"t":"عیسی از اوپرسیده، گفت: «نام تو چیست؟» گفت: «لجئون.» زیرا که دیوهای بسیار داخل او شده بودند."},{"v":31,"t":"واز او استدعا کردند که ایشان را نفرماید که به هاویه روند."},{"v":32,"t":"و در آن نزدیکی گله گراز بسیاری بودند که در کوه می‌چریدند. پس از او خواهش نمودند که بدیشان اجازت دهد تا در آنها داخل شوند. پس ایشان را اجازت داد."},{"v":33,"t":"ناگاه دیوها از آن آدم بیرون شده، داخل گرازان گشتند که آن گله ازبلندی به دریاچه جسته، خفه شدند."},{"v":34,"t":"چون گرازبانان ماجرا را دیدند فرار کردند و در شهر واراضی آن شهرت دادند."},{"v":35,"t":"پس مردم بیرون آمده تا آن واقعه را ببینندنزد عیسی رسیدند و چون آدمی را که از او دیوهابیرون رفته بودند، دیدند که نزد پایهای عیسی رخت پوشیده و عاقل گشته نشسته است ترسیدند."},{"v":36,"t":"و آنانی که این را دیده بودند ایشان راخبر دادند که آن دیوانه چطور شفا یافته بود."},{"v":37,"t":"پس تمام خلق مرزوبوم جدریان از او خواهش نمودند که از نزد ایشان روانه شود، زیرا خوفی شدید بر ایشان مستولی شده بود. پس او به کشتی سوار شده مراجعت نمود."},{"v":38,"t":"اما آن شخصی که دیوها از وی بیرون رفته بودند از او درخواست کرد که با وی باشد. لیکن عیسی او را روانه فرموده، گفت:"},{"v":39,"t":"«به خانه خود برگرد و آنچه خدا با تو کرده است حکایت کن.» پس رفته درتمام شهر از آنچه عیسی بدو نموده بود موعظه کرد."},{"v":40,"t":"و چون عیسی مراجعت کرد خلق او راپذیرفتند زیرا جمیع مردم چشم به راه اومی داشتند."},{"v":41,"t":"که ناگاه مردی، یایرس نام که رئیس کنیسه بود به پایهای عیسی افتاده، به اوالتماس نمود که به خانه او بیاید."},{"v":42,"t":"زیرا که او رادختر یگانه‌ای قریب به دوازده ساله بود که مشرف بر موت بود. و چون می‌رفت خلق بر اوازدحام می‌نمودند."},{"v":43,"t":"ناگاه زنی که مدت دوازده سال به استحاضه مبتلا بود و تمام مایملک خود را صرف اطبانموده و هیچ‌کس نمی توانست او را شفا دهد،"},{"v":44,"t":"از پشت سر وی آمده، دامن ردای او را لمس نمود که در ساعت جریان خونش ایستاد."},{"v":45,"t":"پس عیسی گفت: «کیست که مرا لمس نمود.» چون همه انکار کردند، پطرس و رفقایش گفتند: «ای استاد مردم هجوم آورده بر تو ازدحام می‌کنند ومی گویی کیست که مرا لمس نمود؟»"},{"v":46,"t":"عیسی گفت: «البته کسی مرا لمس نموده است، زیرا که من درک کردم که قوتی از من بیرون شد.»"},{"v":47,"t":"چون آن زن دید که نمی تواند پنهان ماند، لرزان شده، آمد و نزد وی افتاده پیش همه مردم گفت که به چه سبب او را لمس نمود و چگونه فور شفا یافت."},{"v":48,"t":"وی را گفت: «ای دختر خاطرجمع دار، ایمانت تو را شفا داده است، به سلامتی برو.»"},{"v":49,"t":"و این سخن هنوز بر زبان او بود که یکی ازخانه رئیس کنیسه آمده به وی گفت: «دخترت مرد. دیگر استاد را زحمت مده.»"},{"v":50,"t":"چون عیسی این را شنید توجه نموده به وی گفت: «ترسان مباش، ایمان آور و بس که شفا خواهد یافت.»"},{"v":51,"t":"و چون داخل خانه شد، جز پطرس و یوحنا ویعقوب و پدر و مادر دختر هیچ‌کس را نگذاشت که به اندرون آید."},{"v":52,"t":"و چون همه برای او گریه وزاری می‌کردند او گفت: «گریان مباشید نمرده بلکه خفته است.»"},{"v":53,"t":"پس به او استهزا کردندچونکه می‌دانستند که مرده است."},{"v":54,"t":"پس او همه را بیرون کرد و دست دختر را گرفته صدا زد وگفت: «ای دختر برخیز.»"},{"v":55,"t":"و روح او برگشت وفور برخاست. پس عیسی فرمود تا به وی خوراک دهند."},{"v":56,"t":"و پدر و مادر او حیران شدند. پس ایشان را فرمود که هیچ‌کس را از این ماجراخبر ندهند."}]},"9":{"fa":[{"v":1,"t":"پس دوازده شاگرد خود را طلبیده، به ایشان قوت و قدرت بر جمیع دیوها و شفادادن امراض عطا فرمود."},{"v":2,"t":"و ایشان را فرستاد تا به ملکوت خدا موعظه کنند و مریضان را صحت بخشند."},{"v":3,"t":"و بدیشان گفت: «هیچ‌چیز بجهت راه برمدارید نه عصا و نه توشه‌دان و نه نان و نه پول ونه برای یک نفر دو جامه."},{"v":4,"t":"و به هرخانه‌ای که داخل شوید همان جا بمانید تا از آن موضع روانه شوید."},{"v":5,"t":"و هر‌که شما را نپذیرد، وقتی که از آن شهر بیرون شوید خاک پایهای خود را نیزبیفشانید تا بر ایشان شهادتی شود.»"},{"v":6,"t":"پس بیرون شده در دهات می‌گشتند و بشارت می‌دادند و درهرجا صحت می‌بخشیدند."},{"v":7,"t":"اما هیرودیس تیترارک، چون خبر تمام این وقایع را شنید مضطرب شد، زیرا بعضی می‌گفتندکه یحیی از مردگان برخاسته است،"},{"v":8,"t":"و بعضی که الیاس ظاهر شده و دیگران، که یکی از انبیای پیشین برخاسته است."},{"v":9,"t":"اما هیرودیس گفت «سریحیی را از تنش من جدا کردم ولی این کیست که درباره او چنین خبر می‌شنوم» و طالب ملاقات وی می‌بود."},{"v":10,"t":"و چون رسولان مراجعت کردند، آنچه کرده بودند بدو بازگفتند. پس ایشان را برداشته به ویرانه‌ای نزدیک شهری که بیت صیدا نام داشت به خلوت رفت."},{"v":11,"t":"اما گروهی بسیار اطلاع یافته در عقب وی شتافتند. پس ایشان را پذیرفته، ایشان را از ملکوت خدا اعلام می‌نمود و هر‌که احتیاج به معالجه می‌داشت صحت می‌بخشید."},{"v":12,"t":"و چون روز رو به زوال نهاد، آن دوازده نزدوی آمده، گفتند: «مردم را مرخص فرما تا به دهات و اراضی این حوالی رفته منزل و خوراک برای خویشتن پیدا نمایند، زیرا که در اینجا درصحرا می‌باشیم.»"},{"v":13,"t":"او بدیشان گفت: «شماایشان را غذا دهید.» گفتند: «ما را جز پنج نان و دوماهی نیست مگر برویم و بجهت جمیع این گروه غدا بخریم.»"},{"v":14,"t":"زیرا قریب به پنجهزار مرد بودند. پس به شاگردان خود گفت که ایشان را پنجاه پنجاه، دسته دسته، بنشانند.»"},{"v":15,"t":"ایشان همچنین کرده همه را نشانیدند."},{"v":16,"t":"پس آن پنج نان و دوماهی را گرفته، به سوی آسمان نگریست و آنها رابرکت داده، پاره نمود و به شاگردان خود داد تاپیش مردم گذارند."},{"v":17,"t":"پس همه خورده سیرشدند. و دوازده سبد پر از پاره های باقی‌مانده برداشتند."},{"v":18,"t":"و هنگامی که او به تنهایی دعا می‌کرد وشاگردانش همراه او بودند، از ایشان پرسیده، گفت: «مردم مرا که می‌دانند؟»"},{"v":19,"t":"در جواب گفتند: «یحیی تعمید‌دهنده و بعضی الیاس ودیگران می‌گویند که یکی از انبیای پیشین برخاسته است.»"},{"v":20,"t":"بدیشان گفت: «شما مرا که می‌دانید؟» پطرس در جواب گفت: «مسیح خدا.»"},{"v":21,"t":"پس ایشان را قدغن بلیغ فرمود که هیچ‌کس را از این اطلاع مدهید."},{"v":22,"t":"و گفت: «لازم است که پسر انسان زحمت بسیار بیند و از مشایخ وروسای کهنه و کاتبان رد شده کشته شود و روزسوم برخیزد.»"},{"v":23,"t":"پس به همه گفت: «اگر کسی بخواهد مراپیروی کند می‌باید نفس خود را انکار نموده، صلیب خود را هر روزه بردارد و مرا متابعت کند."},{"v":24,"t":"زیرا هر‌که بخواهد جان خود را خلاصی دهدآن را هلاک سازد و هر کس جان خود را بجهت من تلف کرد، آن را نجات خواهد داد."},{"v":25,"t":"زیراانسان را چه فایده دارد که تمام جهان را ببرد ونفس خود را بر باد دهد یا آن را زیان رساند."},{"v":26,"t":"زیرا هر‌که از من و کلام من عار دارد پسر انسان نیز وقتی که در جلال خود و جلال پدر و ملائکه مقدسه آید از او عار خواهد داشت."},{"v":27,"t":"لیکن هرآینه به شما می‌گویم که بعضی از حاضرین دراینجا هستند که تا ملکوت خدا را نبینند ذائقه موت را نخواهند چشید.»"},{"v":28,"t":"و از این کلام قریب به هشت روز گذشته بود که پطرس و یوحنا و یعقوب را برداشته برفراز کوهی برآمد تا دعا کند."},{"v":29,"t":"و چون دعامی کرد هیات چهره او متبدل گشت و لباس اوسفید و درخشان شد."},{"v":30,"t":"که ناگاه دو مرد یعنی موسی و الیاس با وی ملاقات کردند."},{"v":31,"t":"و به هیات جلالی ظاهر شده درباره رحلت او که می‌بایست به زودی در اورشلیم واقع شود گفتگومی کردند."},{"v":32,"t":"اما پطرس و رفقایش را خواب در ربود. پس بیدار شده جلال او و آن دو مرد را که با وی بودند، دیدند."},{"v":33,"t":"و چون آن دو نفر از او جدامی شدند، پطرس به عیسی گفت که «ای استاد، بودن ما در اینجا خوب است. پس سه سایبان بسازیم یکی برای تو و یکی برای موسی ودیگری برای الیاس.» زیرا که نمی دانست چه می‌گفت."},{"v":34,"t":"و این سخن هنوز بر زبانش می‌بود که ناگاه ابری پدیدار شده بر ایشان سایه افکند وچون داخل ابر می‌شدند، ترسان گردیدند."},{"v":35,"t":"آنگاه صدایی از ابر برآمد که «این است پسرحبیب من، او را بشنوید.»"},{"v":36,"t":"و چون این آوازرسید عیسی را تنها یافتند و ایشان ساکت ماندندو از آنچه دیده بودند هیچ‌کس را در آن ایام خبرندادند."},{"v":37,"t":"و در روز بعد چون ایشان از کوه به زیرآمدند، گروهی بسیار او را استقبال نمودند."},{"v":38,"t":"که ناگاه مردی از آن میان فریادکنان گفت: «ای استادبه تو التماس می‌کنم که بر پسر من لطف فرمایی زیرا یگانه من است."},{"v":39,"t":"که ناگاه روحی او رامی گیرد و دفعه صیحه می‌زند و کف کرده مصروع می‌شود و او را فشرده به دشواری رها می‌کند."},{"v":40,"t":"و از شاگردانت درخواست کردم که او را بیرون کنند نتوانستند.»"},{"v":41,"t":"عیسی در جواب گفت: «ای فرقه بی‌ایمان کج روش، تا کی با شما باشم و متحمل شما گردم. پسر خود را اینجا بیاور.»"},{"v":42,"t":"و چون او می‌آمددیو او را دریده مصروع نمود. اما عیسی آن روح خبیث را نهیب داده طفل را شفا بخشید وبه پدرش سپرد."},{"v":43,"t":"و همه از بزرگی خدامتحیر شدند و وقتی که همه از تمام اعمال عیسی متعجب شدند به شاگردان خودگفت:"},{"v":44,"t":"«این سخنان را در گوشهای خود فراگیریدزیرا که پسر انسان به‌دستهای مردم تسلیم خواهدشد.»"},{"v":45,"t":"ولی این سخن را درک نکردند و از ایشان مخفی داشته شد که آن را نفهمند و ترسیدند که آن را از وی بپرسند."},{"v":46,"t":"و در میان ایشان مباحثه شد که کدام‌یک ازما بزرگتر است."},{"v":47,"t":"عیسی خیال دل ایشان راملتفت شده طفلی بگرفت و او را نزد خود برپاداشت."},{"v":48,"t":"و به ایشان گفت: «هر‌که این طفل را به نام من قبول کند، مرا قبول کرده باشد و هر‌که مراپذیرد، فرستنده مرا پذیرفته باشد. زیرا هر‌که ازجمیع شما کوچکتر باشد، همان بزرگ خواهدبود.»"},{"v":49,"t":"یوحنا جواب داده گفت: «ای استادشخصی را دیدیم که به نام تو دیوها را اخراج می‌کند و او را منع نمودیم، از آن رو که پیروی مانمی کند.»"},{"v":50,"t":"عیسی بدو گفت: «او را ممانعت مکنید. زیرا هر‌که ضد شما نیست با شماست.»"},{"v":51,"t":"و چون روزهای صعود او نزدیک می‌شدروی خود را به عزم ثابت به سوی اورشلیم نهاد."},{"v":52,"t":"پس رسولان پیش از خود فرستاده، ایشان رفته به بلدی از بلاد سامریان وارد گشتند تا برای اوتدارک بینند."},{"v":53,"t":"اما او را جای ندادند از آن رو که عازم اورشلیم می‌بود."},{"v":54,"t":"و چون شاگردان او، یعقوب و یوحنا این را دیدند گفتند: «ای خداوند آیا می‌خواهی بگوییم که آتش از آسمان باریده اینها را فرو‌گیرد چنانکه الیاس نیز کرد؟"},{"v":55,"t":"آنگاه روی گردانیده بدیشان گفت: «نمی دانید که شما ازکدام نوع روح هستید."},{"v":56,"t":"زیرا که پسر انسان نیامده است تا جان مردم را هلاک سازد بلکه تانجات دهد.» پس به قریه‌ای دیگر رفتند."},{"v":57,"t":"و هنگامی که ایشان می‌رفتند در اثنای راه شخصی بدو گفت: «خداوندا هر جا روی تو رامتابعت کنم.»"},{"v":58,"t":"عیسی به وی گفت: «روباهان راسوراخها است و مرغان هوا را آشیانه‌ها، لیکن پسر انسان را جای سر نهادن نیست.»"},{"v":59,"t":"و به دیگری گفت: «از عقب من بیا.» گفت: «خداوندااول مرا رخصت ده تا بروم پدر خود را دفن کنم.»"},{"v":60,"t":"عیسی وی را گفت: «بگذار مردگان مردگان خود را دفن کنند. اما تو برو و به ملکوت خداموعظه کن.»"},{"v":61,"t":"و کسی دیگر گفت: «خداوندا تورا پیروی می‌کنم لیکن اول رخصت ده تا اهل خانه خود را وداع نمایم.»"},{"v":62,"t":"عیسی وی را گفت: «کسی‌که دست را به شخم زدن دراز کرده از پشت سر نظر کند، شایسته ملکوت خدا نمی باشد.»"}]},"10":{"fa":[{"v":1,"t":"و بعد از این امور، خداوند هفتاد نفر دیگر را نیز تعیین فرموده، ایشان را جفت جفت پیش روی خود به هر شهری و موضعی که خود عزیمت آن داشت، فرستاد."},{"v":2,"t":"پس بدیشان گفت: «حصاد بسیار است و عمله کم. پس ازصاحب حصاد درخواست کنید تا عمله ها برای حصاد خود بیرون نماید."},{"v":3,"t":"بروید، اینک من شما را چون بره‌ها در میان گرگان می‌فرستم."},{"v":4,"t":"وکیسه و توشه‌دان و کفشها با خود برمدارید وهیچ‌کس را در راه سلام منمایید،"},{"v":5,"t":"و در هرخانه‌ای که داخل شوید، اول گویید سلام بر این خانه باد."},{"v":6,"t":"پس هرگاه ابن السلام در آن خانه باشد، سلام شما بر آن قرار گیرد والا به سوی شما راجع شود."},{"v":7,"t":"و در آن خانه توقف نمایید و از آنچه دارند بخورید و بیاشامید، زیرا که مزدور مستحق اجرت خود است و از خانه به خانه نقل مکنید."},{"v":8,"t":"ودر هر شهری که رفتید و شما را پذیرفتند، از آنچه پیش شما گذارند بخورید."},{"v":9,"t":"و مریضان آنجا راشفا دهید و بدیشان گویید ملکوت خدا به شمانزدیک شده است."},{"v":10,"t":"لیکن در هر شهری که رفتیدو شما را قبول نکردند، به کوچه های آن شهربیرون شده بگویید،"},{"v":11,"t":"حتی خاکی که از شهرشما بر ما نشسته است، بر شما می‌افشانیم. لیکن این را بدانید که ملکوت خدا به شما نزدیک شده است."},{"v":12,"t":"و به شما می‌گویم که حالت سدوم در آن روز، از حالت آن شهر سهل تر خواهد بود."},{"v":13,"t":"وای بر تو‌ای خورزین؛ وای بر تو‌ای بیت صیدا، زیرا اگر معجزاتی که در شما ظاهر شددر صور و صیدون ظاهر می‌شد، هرآینه مدتی درپلاس و خاکستر نشسته، توبه می‌کردند."},{"v":14,"t":"لیکن حالت صور و صیدون در روز جزا، از حال شماآسانتر خواهد بود."},{"v":15,"t":"و تو‌ای کفرناحوم که سر به آسمان افراشته‌ای، تا به حهنم سرنگون خواهی شد."},{"v":16,"t":"آنکه شما را شنود، مرا شنیده و کسی‌که شما را حقیر شمارد مرا حقیر شمرده و هر‌که مراحقیر شمارد فرستنده مرا حقیر شمرده باشد.»"},{"v":17,"t":"پس آن هفتاد نفر با خرمی برگشته گفتند: «ای خداوند، دیوها هم به اسم تو اطاعت مامی کنند.»"},{"v":18,"t":"بدیشان گفت: «من شیطان را دیدم که چون برق از آسمان می‌افتد."},{"v":19,"t":"اینک شما راقوت می‌بخشم که ماران و عقربها و تمامی قوت دشمن را پایمال کنید و چیزی به شما ضرر هرگزنخواهد رسانید."},{"v":20,"t":"ولی از این شادی مکنید که ارواح اطاعت شما می‌کنند بلکه بیشتر شاد باشیدکه نامهای شما در آسمان مرقوم است.»"},{"v":21,"t":"در همان ساعت، عیسی در روح وجدنموده گفت: «ای پدر مالک آسمان و زمین، تو راسپاس می‌کنم که این امور را از دانایان وخردمندان مخفی داشتی و بر کودکان مکشوف ساختی. بلی‌ای پدر، چونکه همچنین منظور نظرتو افتاد.»"},{"v":22,"t":"و به سوی شاگردان خود توجه نموده گفت: «همه‌چیز را پدر به من سپرده است. وهیچ‌کس نمی شناسد که پسر کیست، جز پدر و نه که پدر کیست، غیر از پسر و هر‌که پسر بخواهدبرای او مکشوف سازد.»"},{"v":23,"t":"و در خلوت به شاگردان خود التفات فرموده گفت: «خوشابحال چشمانی که آنچه شما می‌بینید، می‌بینند."},{"v":24,"t":"زیرابه شما می‌گویم بسا انبیا و پادشاهان می‌خواستندآنچه شما می‌بینید، بنگرند و ندیدند و آنچه شمامی شنوید، بشنوند و نشنیدند.»"},{"v":25,"t":"ناگاه یکی از فقها برخاسته از روی امتحان به وی گفت: «ای استاد چه کنم تا وارث حیات جاودانی گردم؟»"},{"v":26,"t":"به وی گفت: «در تورات چه نوشته شده است و چگونه می‌خوانی؟»"},{"v":27,"t":"جواب داده، گفت: «اینکه خداوند خدای خود را به تمام دل و تمام نفس و تمام توانایی و تمام فکر خودمحبت نما و همسایه خود را مثل نفس خود.»"},{"v":28,"t":"گفت: «نیکو جواب گفتی. چنین بکن که خواهی زیست.»"},{"v":29,"t":"لیکن او چون خواست خودرا عادل نماید، به عیسی گفت: «و همسایه من کیست؟»"},{"v":30,"t":"عیسی در جواب وی گفت: «مردی که ازاورشلیم به سوی اریحا می‌رفت، به‌دستهای دزدان افتاد و او را برهنه کرده مجروح ساختند واو را نیم مرده واگذارده برفتند."},{"v":31,"t":"اتفاق کاهنی ازآن راه می‌آمد، چون او را بدید از کناره دیگررفت."},{"v":32,"t":"همچنین شخصی لاوی نیز از آنجا عبورکرده نزدیک آمد و بر او نگریسته از کناره دیگربرفت."},{"v":33,"t":"«لیکن شخصی سامری که مسافر بود نزدوی آمده چون او را بدید، دلش بر وی بسوخت."},{"v":34,"t":"پس پیش آمده بر زخمهای او روغن و شراب ریخته آنها را بست واو را بر مرکب خود سوارکرده به‌کاروانسرای رسانید و خدمت او کرد."},{"v":35,"t":"بامدادان چون روانه می‌شد، دو دینار درآورده به‌سرایدار داد و بدو گفت این شخص را متوجه باش و آنچه بیش از این خرج کنی، در حین مراجعت به تو دهم."},{"v":36,"t":"«پس به نظر تو کدام‌یک از این سه نفرهمسایه بود با آن شخص که به‌دست دزدان افتاد؟»"},{"v":37,"t":"گفت: «آنکه بر او رحمت کرد.» عیسی وی را گفت: «برو و تو نیز همچنان کن.»"},{"v":38,"t":"و هنگامی که می‌رفتند او وارد بلدی شد وزنی که مرتاه نام داشت، او را به خانه خودپذیرفت."},{"v":39,"t":"و او را خواهری مریم نام بود که نزدپایهای عیسی نشسته کلام او را می‌شنید."},{"v":40,"t":"امامرتاه بجهت زیادتی خدمت مضطرب می‌بود. پس نزدیک آمده، گفت: «ای خداوند آیا تو راباکی نیست که خواهرم مرا واگذارد که تنهاخدمت کنم، او را بفرما تا مرا یاری کند.»"},{"v":41,"t":"عیسی در جواب وی گفت: «ای مرتاه، ای مرتاه تو در چیزهای بسیار اندیشه و اضطراب داری."},{"v":42,"t":"لیکن یک چیز لازم است و مریم آن نصیب خوب را اختیار کرده است که از او گرفته نخواهد شد.»"}]},"11":{"fa":[{"v":1,"t":"و هنگامی که او در موضعی دعا می‌کردچون فارغ شد، یکی از شاگردانش به وی گفت: «خداوندا دعا کردن را به ما تعلیم نما، چنانکه یحیی شاگردان خود را بیاموخت.»"},{"v":2,"t":"بدیشان گفت: «هرگاه دعا کنید گویید‌ای پدرما که در آسمانی، نام تو مقدس باد. ملکوت توبیاید. اراده تو چنانکه در آسمان است در زمین نیزکرده شود."},{"v":3,"t":"نان کفاف ما را روز به روز به ما بده."},{"v":4,"t":"و گناهان ما را ببخش زیرا که ما نیز هر قرضدار خود را می‌بخشیم. و ما را در آزمایش میاور، بلکه ما را از شریر رهایی ده.»"},{"v":5,"t":"و بدیشان گفت: «کیست از شما که دوستی داشته باشد و نصف شب نزد وی آمده بگوید‌ای دوست سه قرص نان به من قرض ده،"},{"v":6,"t":"چونکه یکی از دوستان من از سفر بر من وارد شده وچیزی ندارم که پیش او گذارم."},{"v":7,"t":"پس او از اندرون در جواب گوید مرا زحمت مده، زیرا که الان دربسته است و بچه های من در رختخواب با من خفته‌اند نمی توانم برخاست تا به تو دهم."},{"v":8,"t":"به شمامی گویم هر‌چند به علت دوستی برنخیزد تا بدودهد، لیکن بجهت لجاجت خواهد برخاست و هرآنچه حاجت دارد، بدو خواهد داد."},{"v":9,"t":"«و من به شما می‌گویم سوال کنید که به شماداده خواهد شد. بطلبید که خواهید یافت. بکوبیدکه برای شما بازکرده خواهد شد."},{"v":10,"t":"زیرا هر‌که سوال کند، یابد و هر‌که بطلبد، خواهد یافت وهرکه کوبد، برای او باز کرده خواهد شد."},{"v":11,"t":"وکیست از شما که پدر باشد و پسرش از او نان خواهد، سنگی بدو دهد یا اگر ماهی خواهد، به عوض ماهی ماری بدو بخشد،"},{"v":12,"t":"یا اگرتخم‌مرغی بخواهد، عقربی بدو عطا کند."},{"v":13,"t":"پس اگر شما با آنکه شریر هستید می‌دانید چیزهای نیکو را به اولاد خود باید داد، چند مرتبه زیادترپدر آسمانی شما روح‌القدس را خواهد داد به هرکه از او سوال کند.»"},{"v":14,"t":"و دیوی را که گنگ بود بیرون می‌کرد وچون دیو بیرون شد، گنگ گویا گردید و مردم تعجب نمودند."},{"v":15,"t":"لیکن بعضی از ایشان گفتند که «دیوها را به یاری بعلزبول رئیس دیوها بیرون می‌کند.»"},{"v":16,"t":"و دیگران از روی امتحان آیتی آسمانی از او طلب نمودند."},{"v":17,"t":"پس او خیالات ایشان را درک کرده بدیشان گفت: «هر مملکتی که برخلاف خود منقسم شود، تباه گردد و خانه‌ای که بر خانه منقسم شود، منهدم گردد."},{"v":18,"t":"پس شیطان نیز اگر به ضد خود منقسم شود سلطنت اوچگونه پایدار بماند. زیرا می‌گویید که من به اعانت بعلزبول دیوها را بیرون می‌کنم."},{"v":19,"t":"پس اگرمن دیوها را به وساطت بعلزبول بیرون می‌کنم، پسران شما به وساطت که آنها را بیرون می‌کنند؟ از اینجهت ایشان داوران بر شما خواهند بود."},{"v":20,"t":"لیکن هرگاه به انگشت خدا دیوها را بیرون می‌کنم، هرآینه ملکوت خدا ناگهان بر شما آمده است."},{"v":21,"t":"وقتی که مرد زورآور سلاح پوشیده خانه خود را نگاه دارد، اموال او محفوظ می‌باشد."},{"v":22,"t":"اما چون شخصی زورآورتر از او آید بر او غلبه یافته همه اسلحه او را که بدان اعتماد می‌داشت، از او می‌گیرد و اموال او را تقسیم می‌کند."},{"v":23,"t":"کسی‌که با من نیست، برخلاف من است و آنکه با من جمع نمی کند، پراکنده می‌سازد."},{"v":24,"t":"چون روح پلید از انسان بیرون آید به مکانهای بی‌آب بطلب آرامی گردش می‌کند وچون نیافت می‌گوید به خانه خود که از آن بیرون آمدم برمی گردم."},{"v":25,"t":"پس چون آید، آن را جاروب کرده شده و آراسته می‌بیند."},{"v":26,"t":"آنگاه می‌رود وهفت روح دیگر، شریرتر از خود برداشته داخل شده در آنجا ساکن می‌گردد و اواخر آن شخص ازاوائلش بدتر می‌شود.»"},{"v":27,"t":"چون او این سخنان را می‌گفت، زنی از آن میان به آواز بلند وی را گفت «خوشابحال آن رحمی که تو را حمل کرد و پستانهایی که مکیدی.»"},{"v":28,"t":"لیکن او گفت: «بلکه خوشابحال آنانی که کلام خدا را می‌شنوند و آن را حفظمی کنند.»"},{"v":29,"t":"و هنگامی که مردم بر او ازدحام می‌نمودند، سخن‌گفتن آغاز کرد که «اینان فرقه‌ای شریرند که آیتی طلب می‌کنند و آیتی بدیشان عطا نخواهدشد، جز آیت یونس نبی."},{"v":30,"t":"زیرا چنانکه یونس برای اهل نینوا آیت شد، همچنین پسر انسان نیزبرای این فرقه خواهد بود."},{"v":31,"t":"ملکه جنوب در روزداوری با مردم این فرقه برخاسته، بر ایشان حکم خواهد کرد زیرا که از اقصای زمین آمد تا حکمت سلیمان را بشنود و اینک در اینجا کسی بزرگتر ازسلیمان است."},{"v":32,"t":"مردم نینوا در روز داوری با این طبقه برخاسته بر ایشان حکم خواهند کرد زیرا که به موعظه یونس توبه کردند و اینک در اینجا کسی بزرگتر از یونس است."},{"v":33,"t":"و هیچ‌کس چراغی نمی افروزد تا آن را درپنهانی یا زیر پیمانه‌ای بگذارد، بلکه بر چراغدان، تا هر‌که داخل شود روشنی را بیند."},{"v":34,"t":"چراغ بدن چشم است، پس مادامی که چشم تو بسیط است تمامی جسدت نیز روشن است و لیکن اگر فاسدباشد، جسد تو نیز تاریک بود."},{"v":35,"t":"پس باحذر باش مبادا نوری که در تو است، ظلمت باشد."},{"v":36,"t":"بنابراین هرگاه تمامی جسم تو روشن باشد وذره‌ای ظلمت نداشته باشد همه‌اش روشن خواهد بود، مثل وقتی که چراغ به تابش خود، تورا روشنایی می‌دهد.»"},{"v":37,"t":"و هنگامی که سخن می‌گفت یکی ازفریسیان از او وعده خواست که در خانه اوچاشت بخورد. پس داخل شده بنشست."},{"v":38,"t":"امافریسی چون دید که پیش از چاشت دست نشست، تعجب نمود."},{"v":39,"t":"خداوند وی را گفت: «همانا شما‌ای فریسیان بیرون پیاله و بشقاب راطاهر می‌سازید ولی درون شما پر از حرص وخباثت است."},{"v":40,"t":"‌ای احمقان آیا او که بیرون راآفرید، اندرون را نیز نیافرید؟"},{"v":41,"t":"بلکه از آنچه دارید، صدقه دهید که اینک همه‌چیز برای شماطاهر خواهد گشت."},{"v":42,"t":"وای بر شما‌ای فریسیان که ده‌یک از نعناع و سداب و هر قسم سبزی رامی دهید و از دادرسی و محبت خدا تجاوزمی نمایید، اینها را می‌باید به‌جا آورید و آنها رانیز ترک نکنید."},{"v":43,"t":"وای بر شما‌ای فریسیان که صدر کنایس و سلام در بازارها را دوست می‌دارید."},{"v":44,"t":"وای بر شما‌ای کاتبان و فریسیان ریاکار زیرا که مانند قبرهای پنهان شده هستید که مردم بر آنها راه می‌روند و نمی دانند.»"},{"v":45,"t":"آنگاه یکی از فقها جواب داده گفت: «ای معلم، بدین سخنان ما را نیز سرزنش می‌کنی؟»"},{"v":46,"t":"گفت «وای بر شما نیز‌ای فقها زیرا که بارهای گران را بر مردم می‌نهید و خود بر آن بارها، یک انگشت خود را نمی گذارید."},{"v":47,"t":"وای بر شما زیراکه مقابر انبیا را بنا می‌کنید و پدران شما ایشان راکشتند."},{"v":48,"t":"پس به‌کارهای پدران خود شهادت می‌دهید و از آنها راضی هستید، زیرا آنها ایشان را کشتند و شما قبرهای ایشان را می‌سازید."},{"v":49,"t":"ازاین‌رو حکمت خدا نیز فرموده است که به سوی ایشان انبیا و رسولان می‌فرستم و بعضی از ایشان را خواهند کشت و بر بعضی جفا کرد،"},{"v":50,"t":"تا انتقام خون جمیع انبیا که از بنای عالم ریخته شد از این طبقه گرفته شود."},{"v":51,"t":"از خون هابیل تا خون زکریاکه در میان مذبح و هیکل کشته شد. بلی به شمامی گویم که از این فرقه بازخواست خواهد شد."},{"v":52,"t":"وای بر شما‌ای فقها، زیرا کلید معرفت رابرداشته‌اید که خود داخل نمی شوید و داخل‌شوندگان را هم مانع می‌شوید.»"},{"v":53,"t":"و چون او این سخنان را بدیشان می‌گفت، کاتبان و فریسیان با او بشدت درآویختند و درمطالب بسیار سوالها از او می‌کردند."},{"v":54,"t":"و در کمین او می‌بودند تا نکته‌ای از زبان او گرفته مدعی اوبشوند."}]},"12":{"fa":[{"v":1,"t":"و در آن میان، وقتی که هزاران از خلق جمع شدند، به نوعی که یکدیگر راپایمال می‌کردند، به شاگردان خود به سخن‌گفتن شروع کرد. «اول آنکه از خمیرمایه فریسیان که ریاکاری است احتیاط کنید."},{"v":2,"t":"زیرا چیزی نهفته نیست که آشکار نشود و نه مستوری که معلوم نگردد."},{"v":3,"t":"بنابراین آنچه در تاریکی گفته‌اید، درروشنایی شنیده خواهد شد و آنچه در خلوتخانه در گوش گفته‌اید بر پشت بامها ندا شود."},{"v":4,"t":"لیکن‌ای دوستان من، به شما می‌گویم از قاتلان جسم که قدرت ندارند بیشتر از این بکنند، ترسان مباشید."},{"v":5,"t":"بلکه به شما نشان می‌دهم که از که باید ترسید، از او بترسید که بعد از کشتن، قدرت دارد که به جهنم بیفکند. بلی به شما می‌گویم از او بترسید."},{"v":6,"t":"آیا پنج گنجشک به دو فلس فروخته نمی شود وحال آنکه یکی از آنها نزد خدا فراموش نمی شود؟"},{"v":7,"t":"بلکه مویهای سر شما همه شمرده شده است. پس بیم مکنید، زیرا که از چندان گنجشک بهتر هستید."},{"v":8,"t":"«لیکن به شما می‌گویم هر‌که نزد مردم به من اقرار کند، پسر انسان نیز پیش فرشتگان خدا او رااقرار خواهد کرد."},{"v":9,"t":"اما هر‌که مرا پیش مردم انکارکند، نزد فرشتگان خدا انکار کرده خواهد شد."},{"v":10,"t":"و هر‌که سخنی برخلاف پسر انسان گوید، آمرزیده شود. اما هر‌که به روح‌القدس کفر گویدآمرزیده نخواهد شد."},{"v":11,"t":"و چون شما را درکنایس و به نزد حکام و دیوانیان برند، اندیشه مکنید که چگونه و به چه نوع حجت آورید یا چه بگویید."},{"v":12,"t":"زیرا که در همان ساعت روح‌القدس شما را خواهد آموخت که چه باید گفت.»"},{"v":13,"t":"و شخصی از آن جماعت به وی گفت: «ای استاد، برادر مرا بفرما تا ارث پدر را با من تقسیم کند.»"},{"v":14,"t":"به وی گفت: «ای مرد که مرا بر شما داوریا مقسم قرار داده است؟»"},{"v":15,"t":"پس بدیشان گفت: «زنهار از طمع بپرهیزید زیرا اگرچه اموال کسی زیاد شود، حیات او از اموالش نیست.»"},{"v":16,"t":"و مثلی برای ایشان آورده، گفت: «شخصی دولتمند را از املاکش محصول وافر پیدا شد."},{"v":17,"t":"پس با خود اندیشیده، گفت چه کنم؟ زیراجایی که محصول خود را انبار کنم، ندارم."},{"v":18,"t":"پس گفت چنین می‌کنم انبارهای خود را خراب کرده، بزرگتر بنا می‌کنم و در آن تمامی حاصل و اموال خود را جمع خواهم کرد."},{"v":19,"t":"و نفس خود راخواهم گفت که‌ای جان اموال فراوان اندوخته شده بجهت چندین سال داری. الحال بیارام و به اکل و شرب و شادی بپرداز."},{"v":20,"t":"خدا وی را گفت‌ای احمق در همین شب جان تو را از تو خواهندگرفت، آنگاه آنچه اندوخته‌ای، از آن که خواهدبود؟"},{"v":21,"t":"همچنین است هر کسی‌که برای خودذخیره کند و برای خدا دولتمند نباشد.»"},{"v":22,"t":"پس به شاگردان خود گفت: «از این جهت به شما می‌گویم که اندیشه مکنید بجهت جان خودکه چه بخورید و نه برای بدن که چه بپوشید."},{"v":23,"t":"جان از خوراک و بدن از پوشاک بهتر است."},{"v":24,"t":"کلاغان را ملاحظه کنید که نه زراعت می‌کنندو نه حصاد و نه گنجی و نه انباری دارند و خدا آنهارا می‌پروراند. آیا شما به چند مرتبه از مرغان بهترنیستید؟"},{"v":25,"t":"و کیست از شما که به فکر بتواندذراعی بر قامت خود افزاید."},{"v":26,"t":"پس هرگاه توانایی کوچکترین کاری را ندارید چرا برای مابقی می اندیشید."},{"v":27,"t":"سوسنهای چمن را بنگریدچگونه نمو می‌کنند و حال آنکه نه زحمت می‌کشند و نه می‌ریسند، اما به شما می‌گویم که سلیمان با همه جلالش مثل یکی از اینها پوشیده نبود."},{"v":28,"t":"پس هرگاه خدا علفی را که امروز درصحرا است و فردا در تنور افکنده می‌شود چنین می‌پوشاند، چقدر بیشتر شما را‌ای سست‌ایمانان."},{"v":29,"t":"پس شما طالب مباشید که چه بخوریدیا چه بیاشامید و مضطرب مشوید."},{"v":30,"t":"زیرا که امت های جهان، همه این چیزها را می‌طلبند، لیکن پدر شما می‌داند که به این چیزها احتیاج دارید."},{"v":31,"t":"بلکه ملکوت خدا را طلب کنید که جمیع این چیزها برای شما افزوده خواهد شد."},{"v":32,"t":"ترسان مباشید‌ای گله کوچک، زیرا که مرضی پدر شما است که ملکوت را به شما عطافرماید."},{"v":33,"t":"آنچه دارید بفروشید و صدقه دهید وکیسه‌ها بسازید که کهنه نشود و گنجی را که تلف نشود، در آسمان جایی که دزد نزدیک نیاید و بیدتباه نسازد."},{"v":34,"t":"زیرا جایی که خزانه شما است، دل شما نیز در آنجا می‌باشد."},{"v":35,"t":"کمرهای خود را بسته چراغهای خود راافروخته بدارید."},{"v":36,"t":"و شما مانند کسانی باشید که انتظار آقای خود را می‌کشند که چه وقت ازعروسی مراجعت کند تا هروقت آید و در رابکوبد، بی‌درنگ برای او بازکنند."},{"v":37,"t":"خوشابحال آن غلامان که آقای ایشان چون آید ایشان را بیداریابد. هر آینه به شما می‌گویم که کمر خود را بسته ایشان را خواهد نشانید و پیش آمده، ایشان راخدمت خواهد کرد."},{"v":38,"t":"و اگر در پاس دوم یا سوم از شب بیاید و ایشان را چنین یابد، خوشا بحال آن غلامان."},{"v":39,"t":"اما این را بدانید که اگر صاحب‌خانه می‌دانست که دزد در چه ساعت می‌آید، بیدارمی ماند و نمی گذاشت که به خانه‌اش نقب زنند."},{"v":40,"t":"پس شما نیز مستعد باشید، زیرا در ساعتی که گمان نمی برید پسر انسان می‌آید.»"},{"v":41,"t":"پطرس به وی گفت: «ای خداوند، آیا این مثل را برای ما زدی یا بجهت همه.»"},{"v":42,"t":"خداوندگفت: «پس کیست آن ناظر امین و دانا که مولای اووی را بر سایر خدام خود گماشته باشد تا آذوقه را در وقتش به ایشان تقسیم کند."},{"v":43,"t":"خوشابحال آن غلام که آقایش چون آید، او را در چنین کارمشغول یابد."},{"v":44,"t":"هرآینه به شما می‌گویم که او رابر همه مایملک خود خواهد گماشت."},{"v":45,"t":"لیکن اگر آن غلام در خاطر خود گوید، آمدن آقایم به طول می‌انجامد و به زدن غلامان و کنیزان و به خوردن و نوشیدن و میگساریدن شروع کند،"},{"v":46,"t":"هرآینه مولای آن غلام آید، در روزی که منتظر او نباشد و در ساعتی که او نداند و او را دوپاره کرده نصیبش را با خیانتکاران قرار دهد."},{"v":47,"t":"«اما آن غلامی که اراده مولای خویش رادانست و خود را مهیا نساخت تا به اراده او عمل نماید، تازیانه بسیار خواهد خورد."},{"v":48,"t":"اما آنکه نادانسته کارهای شایسته ضرب کند، تازیانه کم خواهد خورد. و به هر کسی‌که عطا زیاده شود ازوی مطالبه زیادتر گردد و نزد هر‌که امانت بیشترنهند از او بازخواست زیادتر خواهند کرد."},{"v":49,"t":"من آمدم تا آتشی در زمین افروزم، پس چه می‌خواهم اگر الان در‌گرفته است."},{"v":50,"t":"اما مراتعمیدی است که بیابم و چه بسیار در تنگی هستم، تا وقتی که آن بسر‌آید."},{"v":51,"t":"آیا گمان می‌برید که من آمده‌ام تا سلامتی بر زمین بخشم؟ نی بلکه به شما می‌گویم تفریق را."},{"v":52,"t":"زیرا بعد ازاین پنج نفر که در یک خانه باشند دو از سه و سه ازدو جدا خواهند شد،"},{"v":53,"t":"پدر از پسر و پسر از پدرو مادر از دختر و دختر از مادر و خارسو ازعروس و عروس از خارسو مفارقت خواهندنمود.»"},{"v":54,"t":"آنگاه باز به آن جماعت گفت: «هنگامی که ابری بینید که از مغرب پدید آید، بی‌تامل می‌گویید باران می‌آید و چنین می‌شود."},{"v":55,"t":"و چون دیدید که باد جنوبی می‌وزد، می‌گویید گرما خواهد شد و می‌شود."},{"v":56,"t":"‌ای ریاکاران، می‌توانید صورت زمین و آسمان راتمیز دهید، پس چگونه این زمان رانمی شناسید؟"},{"v":57,"t":"و چرا از خود به انصاف حکم نمی کنید؟"},{"v":58,"t":"و هنگامی که با مدعی خود نزد حاکم می‌روی، در راه سعی کن که از او برهی، مبادا تو رانزد قاضی بکشد و قاضی تو را به‌سرهنگ سپاردو سرهنگ تو را به زندان افکند."},{"v":59,"t":"تو را می‌گویم تا فلس آخر را ادا نکنی، از آنجا هرگز بیرون نخواهی آمد.»"}]},"13":{"fa":[{"v":1,"t":"در آن وقت بعضی آمده او را از جلیلیانی خبر دادند که پیلاطس خون ایشان را با قربانی های ایشان آمیخته بود."},{"v":2,"t":"عیسی در جواب ایشان گفت: «آیا گمان می‌برید که این جلیلیان گناهکارتر بودند از سایر سکنه جلیل ازاین‌رو که چنین زحمات دیدند؟"},{"v":3,"t":"نی، بلکه به شما می‌گویم اگر توبه نکنید، همگی شماهمچنین هلاک خواهید شد."},{"v":4,"t":"یا آن هجده نفری که برج در سلوام بر ایشان افتاده ایشان را هلاک کرد، گمان می‌برید که از جمیع مردمان ساکن اورشلیم، خطاکارتر بودند؟"},{"v":5,"t":"حاشا، بلکه شما رامی گویم که اگر توبه نکنید همگی شما همچنین هلاک خواهید شد.»"},{"v":6,"t":"پس این مثل را آورد که «شخصی درخت انجیری در تاکستان خود غرس نمود و چون آمدتا میوه از آن بجوید، چیزی نیافت."},{"v":7,"t":"پس به باغبان گفت اینک سه سال است می‌آیم که از این درخت انجیر میوه بطلبم و نمی یابم، آن را ببر چرا زمین رانیز باطل سازد."},{"v":8,"t":"در جواب وی گفت، ای آقاامسال هم آن را مهلت ده تا گردش را کنده کودبریزم،"},{"v":9,"t":"پس اگر ثمر آورد والا بعد از آن، آن راببر.»"},{"v":10,"t":"و روز سبت در یکی از کنایس تعلیم می‌داد."},{"v":11,"t":"و اینک زنی که مدت هجده سال روح ضعف می‌داشت و منحنی شده ابد نمی توانست راست بایستد، در آنجا بود."},{"v":12,"t":"چون عیسی او را دید وی را خوانده گفت: «ای زن از ضعف خودخلاص شو.»"},{"v":13,"t":"و دست های خود را بر وی گذارد که در ساعت راست شده، خدا را تمجیدنمود."},{"v":14,"t":"آنگاه رئیس کنیسه غضب نمود، از آنروکه عیسی او را در سبت شفا داد. پس به مردم توجه نموده، گفت: «شش روز است که باید کاربکنید در آنها آمده شفا یابید، نه در روزسبت.»"},{"v":15,"t":"خداوند در جواب او گفت: «ای ریاکار، آیاهر یکی از شما در روز سبت گاو یا الاغ خود را ازآخور باز کرده بیرون نمی برد تا سیرآبش کند؟"},{"v":16,"t":"و این زنی که دختر ابراهیم است و شیطان او رامدت هجده سال تا به حال بسته بود، نمی بایست او را در روز سبت از این بند رها نمود؟»"},{"v":17,"t":"وچون این را بگفت همه مخالفان او خجل گردیدندو جمیع آن گروه شاد شدند، بسبب همه کارهای بزرگ که از وی صادر می‌گشت."},{"v":18,"t":"پس گفت: «ملکوت خدا چه چیز را می‌ماندو آن را به کدام شی تشبیه نمایم."},{"v":19,"t":"دانه خردلی راماند که شخصی گرفته در باغ خود کاشت، پس رویید و درخت بزرگ گردید، بحدی که مرغان هوا آمده در شاخه هایش آشیانه گرفتند.»"},{"v":20,"t":"باز‌گفت: «برای ملکوت خدا چه مثل آورم؟"},{"v":21,"t":"خمیرمایه‌ای را می‌ماند که زنی گرفته در سه پیمانه آرد پنهان ساخت تا همه مخمرشد.»"},{"v":22,"t":"و در شهرها و دهات گشته، تعلیم می‌داد وبه سوی اورشلیم سفر می‌کرد،"},{"v":23,"t":"که شخصی به وی گفت: «ای خداوند آیا کم هستند که نجات یابند؟» او به ایشان گفت:"},{"v":24,"t":"«جد و جهد کنید تااز در تنگ داخل شوید. زیرا که به شما می‌گویم بسیاری طلب دخول خواهند کرد و نخواهندتوانست."},{"v":25,"t":"بعد از آنکه صاحب‌خانه برخیزد ودر را ببندد و شما بیرون ایستاده در را کوبیدن آغاز کنید و گویید خداوندا خداوندا برای ما بازکن. آنگاه وی در جواب خواهد گفت شما رانمی شناسم که از کجا هستید."},{"v":26,"t":"در آن وقت خواهید گفت که در حضور تو خوردیم وآشامیدیم و در کوچه های ما تعلیم دادی."},{"v":27,"t":"بازخواهد گفت، به شما می‌گویم که شما رانمی شناسم از کجا هستید؟ ای همه بدکاران از من دور شوید."},{"v":28,"t":"در آنجا گریه و فشار دندان خواهدبود، چون ابراهیم واسحق و یعقوب و جمیع انبیارا در ملکوت خدا بینید و خود را بیرون افکنده یابید"},{"v":29,"t":"و از مشرق و مغرب و شمال و جنوب آمده در ملکوت خدا خواهند نشست."},{"v":30,"t":"و اینک آخرین هستند که اولین خواهند بود و اولین که آخرین خواهند بود.»"},{"v":31,"t":"در همان روز چند نفر از فریسیان آمده به وی گفتند: «دور شو و از اینجا برو زیرا که هیرودیس می‌خواهد تو را به قتل رساند.»"},{"v":32,"t":"ایشان را گفت: «بروید و به آن روباه گوییداینک امروز و فردا دیوها را بیرون می‌کنم ومریضان را صحت می‌بخشم و در روز سوم کامل خواهم شد."},{"v":33,"t":"لیکن می‌باید امروز و فردا و پس‌فردا راه روم، زیرا که محال است نبی بیرون ازاورشلیم کشته شود."},{"v":34,"t":"‌ای اورشلیم، ای اورشلیم که قاتل انبیا و سنگسار کننده مرسلین خودهستی، چند کرت خواستم اطفال تو را جمع کنم، چنانکه مرغ جوجه های خویش را زیر بالهای خود می‌گیرد و نخواستید."},{"v":35,"t":"اینک خانه شمابرای شما خراب گذاشته می‌شود و به شمامی گویم که مرا دیگر نخواهید دید تا وقتی آیدکه گویید مبارک است او که به نام خداوندمی آید.»"}]},"14":{"fa":[{"v":1,"t":"و واقع شد که در روز سبت، به خانه یکی از روسای فریسیان برای غذاخوردن درآمد و ایشان مراقب او می‌بودند،"},{"v":2,"t":"واینک شخصی مستسقی پیش او بود،"},{"v":3,"t":"آنگاه عیسی ملتفت شده فقها و فریسیان را خطاب کرده، گفت: «آیا در روز سبت شفا دادن جایزاست؟»"},{"v":4,"t":"ایشان ساکت ماندند. پس آن مرد راگرفته، شفا داد و رها کرد."},{"v":5,"t":"و به ایشان روی آورده، گفت: «کیست از شما که الاغ یا گاوش روزسبت در چاهی افتد و فور آن را بیرون نیاورد؟»"},{"v":6,"t":"پس در این امور از جواب وی عاجزماندند."},{"v":7,"t":"و برای مهمانان مثلی زد، چون ملاحظه فرمود که چگونه صدر مجلس را اختیارمی کردند. پس به ایشان گفت:"},{"v":8,"t":"«چون کسی تو رابه عروسی دعوت کند، در صدر مجلس منشین، مبادا کسی بزرگتر از تو را هم وعده خواسته باشد."},{"v":9,"t":"پس آن کسی‌که تو و او را وعده خواسته بودبیاید و تو را گوید این کس را جای بده و تو باخجالت روی به صف نعال خواهی نهاد."},{"v":10,"t":"بلکه چون مهمان کسی باشی، رفته در پایین بنشین تاوقتی که میزبانت آید به تو گوید، ای دوست برترنشین آنگاه تو را در حضور مجلسیان عزت خواهد بود."},{"v":11,"t":"زیرا هر‌که خود را بزرگ سازدذلیل گردد و هر‌که خویشتن را فرود آرد، سرافرازگردد.»"},{"v":12,"t":"پس به آن کسی‌که از او وعده خواسته بود نیز گفت: «وقتی که چاشت یا شام دهی دوستان یا برادران یا خویشان یا همسایگان دولتمند خود را دعوت مکن مبادا ایشان نیز تو رابخوانند و تو را عوض داده شود."},{"v":13,"t":"بلکه چون ضیافت کنی، فقیران و لنگان و شلان و کوران رادعوت کن."},{"v":14,"t":"که خجسته خواهی بود زیرا ندارندکه تو را عوض دهند و در قیامت عادلان، به توجزا عطا خواهد شد.»"},{"v":15,"t":"آنگاه یکی از مجلسیان چون این سخن راشنید گفت: «خوشابحال کسی‌که در ملکوت خداغذا خورد.»"},{"v":16,"t":"به وی گفت: «شخصی ضیافتی عظیم نمود و بسیاری را دعوت نمود."},{"v":17,"t":"پس چون وقت شام رسید، غلام خود را فرستاد تادعوت‌شدگان را گوید، بیایید زیرا که الحال همه‌چیز حاضر است."},{"v":18,"t":"لیکن همه به یک رای عذرخواهی آغاز کردند. اولی گفت: مزرعه‌ای خریدم و ناچار باید بروم آن را ببینم، از توخواهش دارم مرا معذور داری."},{"v":19,"t":"و دیگری گفت: پنج جفت گاو خریده‌ام، می‌روم تا آنها رابیازمایم، به تو التماس دارم مرا عفو نمایی."},{"v":20,"t":"سومی گفت: زنی گرفته‌ام و از این سبب نمی توانم بیایم."},{"v":21,"t":"پس آن غلام آمده مولای خود را از این امور مطلع ساخت. آنگاه صاحب‌خانه غضب نموده به غلام خود فرمود: به بازارهاو کوچه های شهر بشتاب و فقیران و لنگان وشلان و کوران را در اینجا بیاور."},{"v":22,"t":"پس غلام گفت: ای آقا آنچه فرمودی شد و هنوز جای باقی است."},{"v":23,"t":"پس آقا به غلام گفت: به راهها و مرزهابیرون رفته، مردم را به الحاح بیاور تا خانه من پرشود."},{"v":24,"t":"زیرا به شما می‌گویم هیچ‌یک از آنانی که دعوت شده بودند، شام مرا نخواهد چشید.»"},{"v":25,"t":"و هنگامی که جمعی کثیر همراه اومی رفتند، روی گردانیده بدیشان گفت:"},{"v":26,"t":"«اگرکسی نزد من آید و پدر، مادر و زن و اولاد وبرادران و خواهران، حتی جان خود را نیز دشمن ندارد، شاگرد من نمی تواند بود."},{"v":27,"t":"و هر‌که صلیب خود را برندارد و از عقب من نیاید، نمی تواندشاگرد من گردد."},{"v":28,"t":"«زیرا کیست از شما که قصد بنای برجی داشته باشد و اول ننشیند تا برآورد خرج آن رابکند که آیا قوت تمام کردن آن دارد یا نه؟"},{"v":29,"t":"که مبادا چون بنیادش نهاد و قادر بر تمام کردنش نشد، هر‌که بیند تمسخرکنان گوید،"},{"v":30,"t":"این شخص عمارتی شروع کرده نتوانست به انجامش رساند."},{"v":31,"t":"یا کدام پادشاه است که برای مقاتله باپادشاه دیگر برود، جز اینکه اول نشسته تامل نماید که آیا با ده هزار سپاه، قدرت مقاومت کسی را دارد که با بیست هزار لشکر بر وی می‌آید؟"},{"v":32,"t":"والا چون او هنوز دور است ایلچی‌ای فرستاده شروط صلح را ازاو درخواست کند."},{"v":33,"t":"«پس همچنین هر یکی از شما که تمام مایملک خود را ترک نکند، نمی تواند شاگرد من شود."},{"v":34,"t":"«نمک نیکو است ولی هرگاه نمک فاسدشد به چه چیز اصلاح پذیرد؟"},{"v":35,"t":"نه برای زمین مصرفی دارد و نه برای مزبله، بلکه بیرونش می‌ریزند. آنکه گوش شنوا دارد بشنود.»"}]},"15":{"fa":[{"v":1,"t":"و چون همه باجگیران و گناهکاران به نزدش می‌آمدند تا کلام او را بشنوند،"},{"v":2,"t":"فریسیان و کاتبان، همهمه‌کنان می‌گفتند: «این شخص، گناهکارن را می‌پذیرد و با ایشان می‌خورد.»"},{"v":3,"t":"پس برای ایشان این مثل را زده، گفت:"},{"v":4,"t":"«کیست از شما که صد گوسفند داشته باشد و یکی از آنها گم شود که آن نود و نه را درصحرا نگذارد و از عقب آن گمشده نرود تا آن رابیابد؟"},{"v":5,"t":"پس چون آن را یافت به شادی بر دوش خود می‌گذارد،"},{"v":6,"t":"و به خانه آمده، دوستان وهمسایگان را می‌طلبد و بدیشان می‌گوید با من شادی کنید زیرا گوسفند گمشده خود را یافته‌ام."},{"v":7,"t":"به شما می‌گویم که بر این منوال خوشی درآسمان رخ می‌نماید به‌سبب توبه یک گناهکاربیشتر از برای نود و نه عادل که احتیاج به توبه ندارند."},{"v":8,"t":"یا کدام زن است که ده درهم داشته باشدهرگاه یک درهم گم شود، چراغی افروخته، خانه را جاروب نکند و به دقت تفحص ننماید تا آن رابیابد؟"},{"v":9,"t":"و چون یافت دوستان و همسایگان خودرا جمع کرده می‌گوید با من شادی کنید زیرادرهم گمشده را پیدا کرده‌ام."},{"v":10,"t":"همچنین به شمامی گویم شادی برای فرشتگان خدا روی می‌دهدبه‌سبب یک خطاکار که توبه کند.»"},{"v":11,"t":"باز‌گفت: «شخصی را دو پسر بود."},{"v":12,"t":"روزی پسر کوچک به پدر خود گفت: ای پدر، رصداموالی که باید به من رسد، به من بده. پس اومایملک خود را بر این دو تقسیم کرد."},{"v":13,"t":"و چندی نگذشت که آن پسر کهتر، آنچه داشت جمع کرده، به ملکی بعید کوچ کرد و به عیاشی ناهنجار، سرمایه خود را تلف نمود."},{"v":14,"t":"و چون تمام راصرف نموده بود، قحطی سخت در آن دیارحادث گشت و او به محتاج شدن شروع کرد."},{"v":15,"t":"پس رفته خود را به یکی از اهل آن ملک پیوست. وی او را به املاک خود فرستاد تاگرازبانی کند."},{"v":16,"t":"و آرزو می‌داشت که شکم خودرا از خرنوبی که خوکان می‌خوردند سیر کند وهیچ‌کس او را چیزی نمی داد."},{"v":17,"t":"«آخر به خود آمده، گفت چقدر از مزدوران پدرم نان فراوان دارند و من از گرسنگی هلاک می‌شوم،"},{"v":18,"t":"برخاسته نزد پدر خود می‌روم و بدوخواهم گفت‌ای پدر به آسمان و به حضور تو گناه کرده‌ام،"},{"v":19,"t":"و دیگر شایسته آن نیستم که پسر توخوانده شوم، مرا چون یکی از مزدوران خودبگیر."},{"v":20,"t":"در ساعت برخاسته به سوی پدر خودمتوجه شد. اما هنوز دور بود که پدرش او را دیده، ترحم نمود و دوان دوان آمده او را در آغوش خود کشیده، بوسید."},{"v":21,"t":"پسر وی را گفت، ای پدربه آسمان و به حضور تو گناه کرده‌ام و بعد از این لایق آن نیستم که پسر تو خوانده شوم."},{"v":22,"t":"لیکن پدر به غلامان خود گفت، جامه بهترین را از خانه آورده بدو بپوشانید و انگشتری بر دستش کنید ونعلین بر پایهایش،"},{"v":23,"t":"و گوساله پرواری را آورده ذبح کنید تا بخوریم و شادی نماییم."},{"v":24,"t":"زیرا که این پسر من مرده بود، زنده گردید و گم شده بود، یافت شد. پس به شادی کردن شروع نمودند."},{"v":25,"t":"اما پسر بزرگ او در مزرعه بود. چون آمده نزدیک به خانه رسید، صدای ساز و رقص راشنید."},{"v":26,"t":"پس یکی از نوکران خود را طلبیده پرسید این چیست؟"},{"v":27,"t":"به وی عرض کرد برادرت آمده و پدرت گوساله پرواری را ذبح کرده است زیرا که او را صحیح باز‌یافت."},{"v":28,"t":"ولی او خشم نموده نخواست به خانه درآید تا پدرش بیرون آمده به او التماس نمود."},{"v":29,"t":"اما او در جواب پدرخود گفت، اینک سالها است که من خدمت توکرده‌ام و هرگز از حکم تو تجاوز نورزیده و هرگزبزغاله‌ای به من ندادی تا با دوستان خود شادی کنم."},{"v":30,"t":"لیکن چون این پسرت آمد که دولت تو رابا فاحشه‌ها تلف کرده است، برای او گوساله پرواری را ذبح کردی."},{"v":31,"t":"او وی را گفت، ای فرزند تو همیشه با من هستی و آنچه از آن من است، مال تو است."},{"v":32,"t":"ولی می‌بایست شادمانی کرد و مسرور شد زیرا که این برادر تو مرده بود، زنده گشت و گم شده بود، یافت گردید.»"}]},"16":{"fa":[{"v":1,"t":"و به شاگردان خود نیز گفت: «شخصی دولتمند را ناظری بود که از او نزد وی شکایت بردند که اموال او را تلف می‌کرد."},{"v":2,"t":"پس او را طلب نموده، وی را گفت، این چیست که درباره تو شنیده‌ام؟ حساب نظارت خود را باز بده زیرا ممکن نیست که بعد از این نظارت کنی."},{"v":3,"t":"ناظر با خود گفت چکنم؟ زیرا مولایم نظارت رااز من می‌گیرد. طاقت زمین‌کندن ندارم و از گدایی نیز عار دارم."},{"v":4,"t":"دانستم چکنم تا وقتی که از نظارت معزول شوم، مرا به خانه خود بپذیرند."},{"v":5,"t":"پس هریکی از بدهکاران آقای خود را طلبیده، به یکی گفت آقایم از تو چند طلب دارد؟"},{"v":6,"t":"گفت صدرطل روغن. بدو گفت سیاهه خود را بگیر ونشسته پنجاه رطل بزودی بنویس."},{"v":7,"t":"باز دیگری را گفت از تو چقدر طلب دارد؟ گفت صد کیل گندم. وی را گفت سیاهه خود را بگیر و هشتادبنویس."},{"v":8,"t":"«پس آقایش، ناظر خائن را آفرین گفت، زیراعاقلانه کار کرد. زیرا ابنای این جهان در طبقه خویش از ابنای نور عاقل تر هستند."},{"v":9,"t":"و من شمارا می‌گویم دوستان از مال بی‌انصافی برای خودپیدا کنید تا چون فانی گردید شما را به خیمه های جاودانی بپذیرند."},{"v":10,"t":"آنکه در اندک امین باشد درامر بزرگ نیز امین بود و آنکه در قلیل خائن بود در کثیر هم خائن باشد."},{"v":11,"t":"و هرگاه در مال بی‌انصافی امین نبودید، کیست که مال حقیقی را به شمابسپارد؟"},{"v":12,"t":"و اگر در مال دیگری دیانت نکردید، کیست که مال خاص شما را به شما دهد؟"},{"v":13,"t":"هیچ خادم نمی تواند دو آقا را خدمت کند. زیرا یا از یکی نفرت می‌کند و با دیگری محبت، یا با یکی می‌پیوندد و دیگری را حقیر می‌شمارد. خدا و مامونا را نمی توانید خدمت نمایید."},{"v":14,"t":"و فریسیانی که زر دوست بودند همه این سخنان را شنیده، او را استهزا نمودند."},{"v":15,"t":"به ایشان گفت، شما هستید که خود را پیش مردم عادل می‌نمایید، لیکن خدا عارف دلهای شماست. زیرا که آنچه نزد انسان مرغوب است، نزد خدا مکروه است."},{"v":16,"t":"تورات و انبیا تا به یحیی بود و از آن وقت بشارت به ملکوت خدا داده می‌شود و هر کس بجد و جهد داخل آن می‌گردد."},{"v":17,"t":"لیکن آسانتر است که آسمان و زمین زایل شود، از آنکه یک نقطه از تورات ساقط گردد."},{"v":18,"t":"هر‌که زن خود را طلاق دهد و دیگری را نکاح کند زانی بود و هر‌که زن مطلقه مردی را به نکاح خویش درآورد، زنا کرده باشد."},{"v":19,"t":"شخصی دولتمند بود که ارغوان و کتان می‌پوشید و هر روزه در عیاشی با جلال بسرمی برد."},{"v":20,"t":"و فقیری مقروح بود ایلعازر نام که او رابر درگاه او می‌گذاشتند،"},{"v":21,"t":"و آرزو می‌داشت که از پاره هایی که از خوان آن دولتمند می‌ریخت، خود را سیر کند. بلکه سگان نیز آمده زبان برزخمهای او می‌مالیدند."},{"v":22,"t":"باری آن فقیر بمرد و فرشتگان، او را به آغوش ابراهیم بردند و آن دولتمند نیز مرد و او را دفن کردند."},{"v":23,"t":"پس چشمان خود را در عالم اموات گشوده، خود رادر عذاب یافت. و ابراهیم را از دور و ایلعازر را درآغوشش دید."},{"v":24,"t":"آنگاه به آواز بلند گفت، ای پدرمن ابراهیم، بر من ترحم فرما و ایلعازر را بفرست تا سر انگشت خود را به آب تر ساخته زبان مراخنک سازد، زیرا در این نار معذبم."},{"v":25,"t":"ابراهیم گفت‌ای فرزند به‌خاطر آور که تو در ایام زندگانی چیزهای نیکوی خود را یافتی و همچنین ایلعازرچیزهای بد را، لیکن او الحال در تسلی است و تودر عذاب."},{"v":26,"t":"و علاوه بر این در میان ما و شماورطه عظیمی است، چنانچه آنانی که می‌خواهنداز اینجا به نزد شما عبور کنند، نمی توانند و نه نشینندگان آنجا نزد ما توانند گذشت."},{"v":27,"t":"گفت‌ای پدر به تو التماس دارم که او را به خانه پدرم بفرستی."},{"v":28,"t":"زیرا که مرا پنج برادر است تا ایشان راآگاه سازد، مبادا ایشان نیز به این مکان عذاب بیایند."},{"v":29,"t":"ابراهیم وی را گفت موسی و انبیا رادارند سخن ایشان را بشنوند."},{"v":30,"t":"گفت نه‌ای پدرما ابراهیم، لیکن اگر کسی از مردگان نزد ایشان رود، توبه خواهند کرد."},{"v":31,"t":"وی را گفت هرگاه موسی و انبیا را نشنوند اگر کسی از مردگان نیزبرخیزد، هدایت نخواهند پذیرفت.»"}]},"17":{"fa":[{"v":1,"t":"و شاگردان خود را گفت: «لابد است ازوقوع لغزشها، لیکن وای بر آن کسی‌که باعث آنها شود."},{"v":2,"t":"او را بهتر می‌بود که سنگ آسیایی بر گردنش آویخته شود و در دریا افکنده شود از اینکه یکی از این کودکان را لغزش دهد."},{"v":3,"t":"احتراز کنید و اگر برادرت به تو خطا ورزد او راتنبیه کن و اگر توبه کند او را ببخش."},{"v":4,"t":"و هرگاه درروزی هفت کرت به تو گناه کند و در روزی هفت مرتبه، برگشته به تو گوید توبه می‌کنم، او راببخش.»"},{"v":5,"t":"آنگاه رسولان به خداوند گفتند: «ایمان ما رازیاد کن.»"},{"v":6,"t":"خداوند گفت: «اگر ایمان به قدر دانه خردلی می‌داشتید، به این درخت افراغ می‌گفتیدکه کنده شده در دریا نشانده شود اطاعت شمامی کرد."},{"v":7,"t":"«اما کیست از شماکه غلامش به شخم کردن یا شبانی مشغول شود و وقتی که از صحرا آید به وی گوید، بزودی بیا و بنشین."},{"v":8,"t":"بلکه آیا بدونمی گوید چیزی درست کن تا شام بخورم و کمرخود را بسته مرا خدمت کن تا بخورم و بنوشم وبعد از آن تو بخور و بیاشام؟"},{"v":9,"t":"آیا از آن غلام منت می‌کشد از آنکه حکمهای او را به‌جا آورد؟ گمان ندارم."},{"v":10,"t":"همچنین شما نیز چون به هر چیزی که مامور شده‌اید عمل کردید، گویید که غلامان بی‌منفعت هستیم زیرا که آنچه بر ما واجب بود به‌جا آوردیم.»"},{"v":11,"t":"و هنگامی که سفر به سوی اورشلیم می‌کرداز میانه سامره و جلیل می‌رفت."},{"v":12,"t":"و چون به قریه‌ای داخل می‌شد ناگاه ده شخص ابرص به استقبال او آمدند و از دور ایستاده،"},{"v":13,"t":"به آواز بلندگفتند: «ای عیسی خداوند بر ما ترحم فرما.»"},{"v":14,"t":"اوبه ایشان نظر کرده گفت: «بروید و خود را به کاهن بنمایید.» ایشان چون می‌رفتند، طاهر گشتند."},{"v":15,"t":"و یکی از ایشان چون دید که شفا یافته است، برگشته به صدای بلند خدا را تمجید می‌کرد."},{"v":16,"t":"وپیش قدم او به روی در‌افتاده وی را شکر کرد. و اواز اهل سامره بود."},{"v":17,"t":"عیسی ملتفت شده گفت «آیا ده نفر طاهر نشدند، پس آن نه کجا شدند؟"},{"v":18,"t":"آیا هیچ‌کس یافت نمی شود که برگشته خدا راتمجید کند جز این غریب؟»"},{"v":19,"t":"و بدو گفت: «برخاسته برو که ایمانت تو را نجات داده است.»"},{"v":20,"t":"و چون فریسیان از او پرسیدند که ملکوت خدا کی می‌آید، او در جواب ایشان گفت: «ملکوت خدا با مراقبت نمی آید."},{"v":21,"t":"و نخواهندگفت که در فلان یا فلان جاست. زیرا اینک ملکوت خدا در میان شما است.»"},{"v":22,"t":"و به شاگردان خود گفت: «ایامی می‌آید که آرزو خواهید داشت که روزی از روزهای پسر انسان را بینید ونخواهید دید."},{"v":23,"t":"و به شما خواهند گفت، اینک در فلان یا فلان جاست، مروید و تعاقب آن مکنید."},{"v":24,"t":"زیرا چون برق که از یک جانب زیرآسمان لامع شده تا جانب دیگر زیر آسمان درخشان می‌شود، پسر انسان در یوم خودهمچنین خواهد بود."},{"v":25,"t":"لیکن اول لازم است که اوزحمات بسیار بیند و از این فرقه مطرود شود."},{"v":26,"t":"و چنانکه در ایام نوح واقع شد، همانطوردر زمان پسر انسان نیز خواهد بود،"},{"v":27,"t":"که می‌خوردند و می‌نوشیدند و زن و شوهرمی گرفتند تا روزی که چون نوح داخل کشتی شد، طوفان آمده همه را هلاک ساخت."},{"v":28,"t":"وهمچنان‌که در ایام لوط شد که به خوردن وآشامیدن و خرید و فروش و زراعت و عمارت مشغول می‌بودند،"},{"v":29,"t":"تا روزی که چون لوط ازسدوم بیرون آمد، آتش و گوگرد از آسمان باریدو همه را هلاک ساخت."},{"v":30,"t":"بر همین منوال خواهدبود در روزی که پسر انسان ظاهر شود."},{"v":31,"t":"در آن روز هر‌که بر پشت بام باشد و اسباب او در خانه نزول نکند تا آنها را بردارد و کسی‌که در صحراباشد همچنین برنگردد."},{"v":32,"t":"زن لوط را بیاد آورید."},{"v":33,"t":"هر‌که خواهد جان خود را برهاند آن را هلاک خواهد کرد و هر‌که آن را هلاک کند آن را زنده نگاه خواهد داشت."},{"v":34,"t":"به شما می‌گویم در آن شب دو نفر بر یک تخت خواهند بود، یکی برداشته و دیگری واگذارده خواهد شد."},{"v":35,"t":"و دوزن که در یک جا دستاس کنند، یکی برداشته ودیگری واگذارده خواهد شد."},{"v":36,"t":"و دونفر که درمزرعه باشند، یکی برداشته و دیگری واگذارده خواهد شد.»"},{"v":37,"t":"در جواب وی گفتند: «کجا‌ای خداوند.» گفت: «در هر جایی که لاش باشد درآنجا کرکسان جمع خواهند شد.»"}]},"18":{"fa":[{"v":1,"t":"و برای ایشان نیز مثلی آورد در اینکه می باید همیشه دعا کرد و کاهلی نورزید."},{"v":2,"t":"پس گفت که «در شهری داوری بود که نه ترس از خدا و نه باکی از انسان می‌داشت."},{"v":3,"t":"ودر همان شهر بیوه‌زنی بود که پیش وی آمده می‌گفت، داد مرا از دشمنم بگیر."},{"v":4,"t":"و تا مدتی به وی اعتناننمود ولکن بعد از آن با خود گفت هرچند از خدا نمی ترسم و از مردم باکی ندارم،"},{"v":5,"t":"لیکن چون این بیوه‌زن مرا زحمت می‌دهد، به داد او می‌رسم، مبادا پیوسته آمده مرا به رنج آورد."},{"v":6,"t":"خداوند گفت بشنوید که این داوربی انصاف چه می‌گوید؟"},{"v":7,"t":"و آیا خدا برگزیدگان خود را که شبانه‌روز بدو استغاثه می‌کنند، دادرسی نخواهد کرد، اگرچه برای ایشان دیرغضب باشد؟"},{"v":8,"t":"به شما می‌گویم که به زودی دادرسی ایشان را خواهد کرد. لیکن چون پسرانسان آید، آیا ایمان را بر زمین خواهدیافت؟"},{"v":9,"t":"و این مثل را آورد برای بعضی که بر خوداعتماد می‌داشتند که عادل بودند و دیگران راحقیر می‌شمردند."},{"v":10,"t":"که «دو نفر یکی فریسی ودیگری باجگیر به هیکل رفتند تا عبادت کنند."},{"v":11,"t":"آن فریسی ایستاده بدینطور با خود دعا کرد که خدایا تو را شکر می‌کنم که مثل سایر مردم حریص و ظالم و زناکار نیستم و نه مثل این باجگیر،"},{"v":12,"t":"هر هفته دو مرتبه روزه می‌دارم و ازآنچه پیدا می‌کنم ده‌یک می‌دهم."},{"v":13,"t":"اما آن باجگیر دور ایستاده نخواست چشمان خود را به سوی آسمان بلند کند بلکه به سینه خود زده گفت، خدایا بر من گناهکار ترحم فرما."},{"v":14,"t":"به شمامی گویم که این شخص، عادل کرده شده به خانه خود رفت به خلاف آن دیگر، زیرا هر‌که خود رابرافرازد، پست گردد و هرکس خویشتن را فروتن سازد، سرافرازی یابد.»"},{"v":15,"t":"پس اطفال را نیز نزد وی آوردند تا دست برایشان گذارد. اما شاگردانش چون دیدند، ایشان رانهیب دادند."},{"v":16,"t":"ولی عیسی ایشان را خوانده، گفت: «بچه‌ها را واگذارید تا نزد من آیند و ایشان را ممانعت مکنید، زیرا ملکوت خدا برای مثل اینها است."},{"v":17,"t":"هرآینه به شما می‌گویم هر‌که ملکوت خدا را مثل طفل نپذیرد داخل آن نگردد.»"},{"v":18,"t":"و یکی از روسا از وی سوال نموده، گفت: «ای استاد نیکو چه کنم تا حیات جاودانی راوارث گردم؟»"},{"v":19,"t":"عیسی وی را گفت: «از بهر‌چه مرا نیکو می‌گویی و حال آنکه هیچ‌کس نیکونیست جز یکی که خدا باشد."},{"v":20,"t":"احکام رامی دانی زنا مکن، قتل مکن، دزدی منما، شهادت دروغ مده و پدر و مادر خود را محترم دار.»"},{"v":21,"t":"گفت: «جمیع اینها را از طفولیت خود نگاه داشته‌ام.»"},{"v":22,"t":"عیسی چون این را شنید بدو گفت: «هنوز تو را یک چیز باقی است. آنچه داری بفروش و به فقرا بده که در آسمان گنجی خواهی داشت، پس آمده مرا متابعت کن.»"},{"v":23,"t":"چون این راشنید محزون گشت، زیرا که دولت فراوان داشت."},{"v":24,"t":"اما عیسی چون او را محزون دید گفت: «چه دشوار است که دولتمندان داخل ملکوت خداشوند."},{"v":25,"t":"زیرا گذشتن شتر از سوراخ سوزن آسانتر است از دخول دولتمندی در ملکوت خدا.»"},{"v":26,"t":"اما شنوندگان گفتند: «پس که می‌تواندنجات یابد؟»"},{"v":27,"t":"او گفت: «آنچه نزد مردم محال است، نزد خدا ممکن است.»"},{"v":28,"t":"پطرس گفت: «اینک ما همه‌چیز را ترک کرده پیروی تو می‌کنیم.»"},{"v":29,"t":"به ایشان گفت: «هرآینه به شما می‌گویم، کسی نیست که خانه یاوالدین یا زن یا برادران یا اولاد را بجهت ملکوت خدا ترک کند،"},{"v":30,"t":"جز اینکه در این عالم چند برابربیابد و در عالم آینده حیات جاودانی را.»"},{"v":31,"t":"پس آن دوازده را برداشته، به ایشان گفت: «اینک به اورشلیم می‌رویم و آنچه به زبان انبیادرباره پسر انسان نوشته شده است، به انجام خواهد رسید."},{"v":32,"t":"زیرا که او را به امت‌ها تسلیم می‌کنند و استهزا و بی‌حرمتی کرده آب دهان بروی انداخته"},{"v":33,"t":"و تازیانه زده او را خواهند کشت ودر روز سوم خواهد برخاست.»"},{"v":34,"t":"اما ایشان چیزی از این امور نفهمیدند و این سخن از ایشان مخفی داشته شد و آنچه می‌گفت، درک نکردند."},{"v":35,"t":"و چون نزدیک اریحا رسید، کوری بجهت گدایی بر سر راه نشسته بود."},{"v":36,"t":"و چون صدای گروهی را که می‌گذشتند شنید، پرسید چه چیزاست؟"},{"v":37,"t":"گفتندش عیسی ناصری در گذر است."},{"v":38,"t":"در حال فریاد برآورده گفت: «ای عیسی، ای پسر داود، بر من ترحم فرما.»"},{"v":39,"t":"و هرچند آنانی که پیش می‌رفتند او را نهیب می‌دادند تا خاموش شود، او بلندتر فریاد می‌زد که پسر داودا بر من ترحم فرما."},{"v":40,"t":"آنگاه عیسی ایستاده فرمود تا او رانزد وی بیاورند. و چون نزدیک شد از وی پرسیده،"},{"v":41,"t":"گفت: «چه می‌خواهی برای توبکنم؟» عرض کرد: «ای خداوند، تا بینا شوم.»"},{"v":42,"t":"عیسی به وی گفت: «بینا شو که ایمانت تو راشفا داده است.»"},{"v":43,"t":"در ساعت بینایی یافته، خدا راتمجید‌کنان از عقب او افتاد و جمیع مردم چون این را دیدند، خدا را تسبیح خواندند."}]},"19":{"fa":[{"v":1,"t":"پس وارد اریحا شده، از آنجا می گذشت."},{"v":2,"t":"که ناگاه شخصی زکی نام که رئیس باجگیران و دولتمند بود،"},{"v":3,"t":"خواست عیسی را ببیند که کیست و از کثرت خلق نتوانست، زیرا کوتاه قد بود."},{"v":4,"t":"پس پیش دویده بردرخت افراغی برآمد تا او را ببیند. چونکه اومی خواست از آن راه عبور کند."},{"v":5,"t":"و چون عیسی به آن مکان رسید، بالا نگریسته او را دید و گفت: «ای زکی بشتاب و به زیر بیا زیرا که باید امروز درخانه تو بمانم.»"},{"v":6,"t":"پس به زودی پایین شده او را به خرمی پذیرفت."},{"v":7,"t":"و همه چون این را دیدند، همهمه‌کنان می‌گفتند که در خانه شخصی گناهکار به میهمانی رفته است."},{"v":8,"t":"اما زکی برپا شده به خداوند گفت: «الحال‌ای خداوند نصف مایملک خود را به فقرامی دهم و اگر چیزی ناحق از کسی گرفته باشم، چهار برابر بدو رد می‌کنم.»"},{"v":9,"t":"عیسی به وی گفت: «امروز نجات در این خانه پیدا شد. زیرا که این شخص هم پسر ابراهیم است."},{"v":10,"t":"زیرا که پسرانسان آمده است تا گمشده را بجوید و نجات‌بخشد.»"},{"v":11,"t":"و چون ایشان این را شنیدند او مثلی زیادکرده آورد چونکه نزدیک به اورشلیم بود و ایشان گمان می‌بردند که ملکوت خدا می‌باید در همان زمان ظهور کند."},{"v":12,"t":"پس گفت: «شخصی شریف به دیار بعید سفر کرد تا ملکی برای خود گرفته مراجعت کند."},{"v":13,"t":"پس ده نفر از غلامان خود راطلبیده ده قنطار به ایشان سپرده فرمود، تجارت کنید تا بیایم."},{"v":14,"t":"اما اهل ولایت او، چونکه او رادشمن می‌داشتند ایلچیان در عقب او فرستاده گفتند، نمی خواهیم این شخص بر ما سلطنت کند."},{"v":15,"t":"و چون ملک را گرفته مراجعت کرده بود، فرمود تا آن غلامانی را که به ایشان نقد سپرده بودحاضر کنند تا بفهمد هر یک چه سود نموده است."},{"v":16,"t":"پس اولی آمده گفت، ای آقا قنطار تو ده قنطار دیگر نفع آورده است."},{"v":17,"t":"بدو گفت آفرین‌ای غلام نیکو. چونکه بر چیز کم امین بودی بر ده شهر حاکم شو."},{"v":18,"t":"و دیگری آمده گفت، ای آقاقنطار تو پنج قنطار سود کرده است."},{"v":19,"t":"او را نیزفرمود بر پنج شهر حکمرانی کن."},{"v":20,"t":"و سومی آمده گفت، ای آقا اینک قنطار تو موجود است، آن را در پارچه‌ای نگاه داشته‌ام."},{"v":21,"t":"زیرا که از توترسیدم چونکه مرد تندخویی هستی. آنچه نگذارده‌ای، برمی داری و از آنچه نکاشته‌ای درومی کنی."},{"v":22,"t":"به وی گفت، از زبان خودت بر توفتوی می‌دهم، ای غلام شریر. دانسته‌ای که من مرد تندخویی هستم که برمیدارم آنچه رانگذاشته‌ام و درو می‌کنم آنچه را نپاشیده‌ام."},{"v":23,"t":"پس برای چه نقد مرا نزد صرافان نگذاردی تاچون آیم آن را با سود دریافت کنم؟"},{"v":24,"t":"پس به حاضرین فرمود قنطار را از این شخص بگیرید وبه صاحب ده قنطار بدهید."},{"v":25,"t":"به او گفتند‌ای خداوند، وی ده قنطار دارد."},{"v":26,"t":"زیرا به شمامی گویم به هر‌که دارد داده شود و هر‌که نداردآنچه دارد نیز از او گرفته خواهد شد."},{"v":27,"t":"اما آن دشمنان من که نخواستند من بر ایشان حکمرانی نمایم، در اینجا حاضر ساخته پیش من به قتل رسانید.»"},{"v":28,"t":"و چون این را گفت، پیش رفته متوجه اورشلیم گردید."},{"v":29,"t":"و چون نزدیک بیت‌فاجی وبیت عنیا بر کوه مسمی به زیتون رسید، دو نفر ازشاگردان خود را فرستاده،"},{"v":30,"t":"گفت: «به آن قریه‌ای که پیش روی شما است بروید و چون داخل آن شدید، کره الاغی بسته خواهید یافت که هیچ‌کس بر آن هرگز سوار نشده. آن را باز کرده بیاورید."},{"v":31,"t":"و اگر کسی به شما گوید، چرا این راباز می‌کنید، به وی گویید خداوند او را لازم دارد.»"},{"v":32,"t":"پس فرستادگان رفته آن چنانکه بدیشان گفته بود یافتند."},{"v":33,"t":"و چون کره را باز می‌کردند، مالکانش به ایشان گفتند چرا کره را باز می‌کنید؟"},{"v":34,"t":"گفتند خداوند او را لازم دارد."},{"v":35,"t":"پس او را به نزد عیسی آوردند و رخت خود را بر کره افکنده، عیسی را سوار کردند."},{"v":36,"t":"و هنگامی که او می‌رفت جامه های خود را در راه می‌گستردند."},{"v":37,"t":"و چون نزدیک به‌سرازیری کوه زیتون رسید، تمامی شاگردانش شادی کرده، به آوازبلند خدا را حمد گفتن شروع کردند، به‌سبب همه قواتی که از او دیده بودند."},{"v":38,"t":"و می‌گفتند مبارک باد آن پادشاهی که می‌آید، به نام خداوند سلامتی در آسمان و جلال در اعلی علیین باد."},{"v":39,"t":"آنگاه بعضی از فریسیان از آن میان بدو گفتند: «ای استاد شاگردان خود را نهیب نما.»"},{"v":40,"t":"او درجواب ایشان گفت: «به شما می‌گویم اگراینها ساکت شوند، هرآینه سنگها به صداآیند.»"},{"v":41,"t":"و چون نزدیک شده، شهر را نظاره کرد برآن گریان گشته،"},{"v":42,"t":"گفت: «اگر تو نیز می‌دانستی هم در این زمان خود آنچه باعث سلامتی تومیشد، لاکن الحال از چشمان تو پنهان گشته است."},{"v":43,"t":"زیرا ایامی بر تو می‌آید که دشمنانت گرد تو سنگرها سازند و تو را احاطه کرده از هرجانب محاصره خواهند نمود."},{"v":44,"t":"و تو را وفرزندانت را در اندرون تو بر خاک خواهند افکندو در تو سنگی بر سنگی نخواهند گذاشت زیرا که ایام تفقد خود را ندانستی.»"},{"v":45,"t":"و چون داخل هیکل شد، کسانی را که درآنجا خرید و فروش می‌کردند، به بیرون نمودن آغاز کرد."},{"v":46,"t":"و به ایشان گفت: «مکتوب است که خانه من خانه عبادت است لیکن شما آن را مغاره دزدان ساخته‌اید.»"},{"v":47,"t":"و هر روز در هیکل تعلیم می‌داد، اما روسای کهنه و کاتبان و اکابر قوم قصدهلاک نمودن او می‌کردند."},{"v":48,"t":"و نیافتند چه کنندزیرا که تمامی مردم بر او آویخته بودند که از اوبشنوند."}]},"20":{"fa":[{"v":1,"t":"روزی از آن روزها واقع شد هنگامی که او قوم را در هیکل تعلیم و بشارت می‌داد که روسا کهنه و کاتبان با مشایخ آمده،"},{"v":2,"t":"به وی گفتند: «به ما بگو که به چه قدرت این کارها رامی کنی و کیست که این قدرت را به تو داده است؟»"},{"v":3,"t":"در جواب ایشان گفت: «من نیز از شماچیزی می‌پرسم. به من بگویید."},{"v":4,"t":"تعمید یحیی ازآسمان بود یا از مردم؟»"},{"v":5,"t":"ایشان با خود اندیشیده، گفتند که اگر گوییم از آسمان، هرآینه گوید چرا به او ایمان نیاوردید؟"},{"v":6,"t":"و اگر گوییم از انسان، تمامی قوم ما را سنگسار کنند زیرا یقین می‌دارند که یحیی نبی است.»"},{"v":7,"t":"پس جواب دادند که «نمی دانیم از کجا بود.»"},{"v":8,"t":"عیسی به ایشان گفت: «من نیز شما را نمی گویم که این کارها را به چه قدرت به‌جا می‌آورم.»"},{"v":9,"t":"و این مثل را به مردم گفتن گرفت که «شخصی تاکستانی غرس کرد و به باغبانش سپرده مدت مدیدی سفر کرد."},{"v":10,"t":"و در موسم غلامی نزدباغبانان فرستاد تا از میوه باغ بدو سپارند. اماباغبانان او را زده، تهی‌دست بازگردانیدند."},{"v":11,"t":"پس غلامی دیگر روانه نمود. او را نیز تازیانه زده بی‌حرمت کرده، تهی‌دست بازگردانیدند."},{"v":12,"t":"و بازسومی فرستاد. او را نیز مجروح ساخته بیرون افکندند."},{"v":13,"t":"آنگاه صاحب باغ گفت چه کنم؟ پسرحبیب خود را می‌فرستم شاید چون او را بینند احترام خواهند نمود."},{"v":14,"t":"اما چون باغبانان او رادیدند، با خود تفکرکنان گفتند، این وارث می‌باشد، بیایید او را بکشیم تا میراث از آن ماگردد."},{"v":15,"t":"در حال او را از باغ بیرون افکنده کشتند. پس صاحب باغ بدیشان چه خواهد کرد؟"},{"v":16,"t":"اوخواهد آمد و باغبانان را هلاک کرده باغ را به دیگران خواهد سپرد.» پس چون شنیدند گفتندحاشا."},{"v":17,"t":"به ایشان نظر افکنده گفت: «پس معنی‌این نوشته چیست، سنگی را که معماران ردکردند، همان سر زاویه شده است."},{"v":18,"t":"و هر‌که برآن سنگ افتد خرد شود، اما اگر آن بر کسی بیفتداو را نرم خواهد ساخت؟»"},{"v":19,"t":"آنگاه روسای کهنه و کاتبان خواستند که در همان ساعت او را گرفتارکنند. لیکن از قوم ترسیدند زیرا که دانستند که این مثل را درباره ایشان زده بود."},{"v":20,"t":"و مراقب او بوده جاسوسان فرستادند که خود را صالح می‌نمودند تا سخنی از او گرفته، اورا به حکم و قدرت والی بسپارند."},{"v":21,"t":"پس از اوسوال نموده گفتند: «ای استاد می‌دانیم که تو به راستی سخن می‌رانی و تعلیم می‌دهی و از کسی روداری نمی کنی، بلکه طریق خدا را به صدق می‌آموزی،"},{"v":22,"t":"آیا بر ما جایز هست که جزیه به قیصر بدهیم یا نه؟»"},{"v":23,"t":"او چون مکر ایشان را درک کرد، بدیشان گفت: «مرا برای چه امتحان می‌کنید؟"},{"v":24,"t":"دیناری به من نشان دهید. صورت ورقمش از کیست؟ «ایشان در جواب گفتند: «از قیصر است.»"},{"v":25,"t":"او به ایشان گفت: «پس مال قیصررا به قیصر رد کنید و مال خدا را به خدا.»"},{"v":26,"t":"پس چون نتوانستند او را به سخنی در نظر مردم ملزم سازند، از جواب او در عجب شده ساکت ماندند."},{"v":27,"t":"و بعضی از صدوقیان که منکر قیامت هستند، پیش آمده از وی سوال کرده،"},{"v":28,"t":"گفتند: «ای استاد، موسی برای ما نوشته است که اگرکسی را برادری که زن داشته باشد بمیرد وبی اولاد فوت شود، باید برادرش آن زن را بگیردتا برای برادر خود نسلی آورد."},{"v":29,"t":"پس هفت برادربودند که اولی زن گرفته اولاد ناآورده، فوت شد."},{"v":30,"t":"بعد دومین آن زن را گرفته، او نیز بی‌اولاد بمرد."},{"v":31,"t":"پس سومین او را گرفت و همچنین تا هفتمین وهمه فرزند ناآورده، مردند."},{"v":32,"t":"و بعد از همه، آن زن نیز وفات یافت."},{"v":33,"t":"پس در قیامت، زن کدام‌یک از ایشان خواهد بود، زیرا که هر هفت او راداشتند؟»"},{"v":34,"t":"عیسی در جواب ایشان گفت: «ابنای این عالم نکاح می‌کنند و نکاح کرده می‌شوند."},{"v":35,"t":"لیکن آنانی که مستحق رسیدن به آن عالم و به قیامت از مردگان شوند، نه نکاح می‌کنند و نه نکاح کرده می‌شوند."},{"v":36,"t":"زیرا ممکن نیست که دیگربمیرند از آن جهت که مثل فرشتگان و پسران خدامی باشند، چونکه پسران قیامت هستند."},{"v":37,"t":"و امااینکه مردگان برمی خیزند، موسی نیز در ذکر بوته نشان داد، چنانکه خداوند را خدای ابراهیم وخدای اسحاق و خدای یعقوب خواند."},{"v":38,"t":"و حال آنکه خدای مردگان نیست بلکه خدای زندگان است. زیرا همه نزد او زنده هستند.»"},{"v":39,"t":"پس بعضی از کاتبان در جواب گفتند: «ای استاد. نیکوگفتی.»"},{"v":40,"t":"و بعد از آن هیچ‌کس جرات آن نداشت که از وی سوالی کند."},{"v":41,"t":"پس به ایشان گفت: «چگونه می‌گویند که مسیح پسر داود است"},{"v":42,"t":"و خود داود در کتاب زبور می‌گوید، خداوند به خداوند من گفت به‌دست راست من بنشین"},{"v":43,"t":"تا دشمنان تو راپای انداز تو سازم؟"},{"v":44,"t":"پس چون داود او راخداوند می‌خواند چگونه پسر او می‌باشد؟»"},{"v":45,"t":"و چون تمامی قوم می‌شنیدند، به شاگردان خود گفت:"},{"v":46,"t":"«بپرهیزید از کاتبانی که خرامیدن در لباس دراز را می‌پسندند و سلام در بازارها وصدر کنایس و بالا نشستن در ضیافتها را دوست می‌دارند."},{"v":47,"t":"و خانه های بیوه‌زنان را می‌بلعند ونماز را به ریاکاری طول می‌دهند. اینها عذاب شدیدتر خواهند یافت.»"}]},"21":{"fa":[{"v":1,"t":"و نظر کرده دولتمندانی را دید که هدایای خود را در بیت‌المال می‌اندازند."},{"v":2,"t":"و بیوه‌زنی فقیر را دید که دو فلس در آنجا انداخت."},{"v":3,"t":"پس گفت: «هرآینه به شمامی گویم این بیوه فقیر از جمیع آنها بیشترانداخت."},{"v":4,"t":"زیرا که همه ایشان از زیادتی خود درهدایای خدا انداختند، لیکن این زن از احتیاج خود تمامی معیشت خویش را انداخت."},{"v":5,"t":"و چون بعضی ذکر هیکل می‌کردند که به سنگهای خوب و هدایا آراسته شده است گفت:"},{"v":6,"t":"«ایامی می‌آید که از این چیزهایی که می‌بینید، سنگی بر سنگی گذارده نشود، مگر اینکه به زیرافکنده خواهد شد."},{"v":7,"t":"و از او سوال نموده، گفتند: «ای استاد پس این امور کی واقع می‌شود وعلامت نزدیک شدن این وقایع چیست؟»"},{"v":8,"t":"گفت: «احتیاط کنید که گمراه نشوید. زیرا که بسا به نام من آمده خواهند گفت که من هستم و وقت نزدیک است. پس از عقب ایشان مروید."},{"v":9,"t":"و چون اخبارجنگها و فسادها را بشنوید، مضطرب مشویدزیرا که وقوع این امور اول ضرور است لیکن انتهادر ساعت نیست.»"},{"v":10,"t":"پس به ایشان گفت: «قومی با قومی ومملکتی با مملکتی مقاومت خواهند کرد."},{"v":11,"t":"وزلزله های عظیم در جایها و قحطیها و وباها پدیدو چیزهای هولناک و علامات بزرگ از آسمان ظاهر خواهد شد."},{"v":12,"t":"و قبل از این همه، بر شمادست اندازی خواهند کرد و جفا نموده شما را به کنایس و زندانها خواهند سپرد و در حضورسلاطین و حکام بجهت نام من خواهند برد."},{"v":13,"t":"واین برای شما به شهادت خواهد انجامید."},{"v":14,"t":"پس در دلهای خود قرار دهید که برای حجت آوردن، پیشتر اندیشه نکنید،"},{"v":15,"t":"زیرا که من به شما زبانی وحکمتی خواهم داد که همه دشمنان شما با آن مقاومت و مباحثه نتوانند نمود."},{"v":16,"t":"و شما راوالدین و برادران و خویشان و دوستان تسلیم خواهند کرد و بعضی از شما را به قتل خواهندرسانید."},{"v":17,"t":"و جمیع مردم به جهت نام من شما رانفرت خواهند کرد."},{"v":18,"t":"ولکن مویی از سر شما گم نخواهد شد."},{"v":19,"t":"جانهای خود را به صبر دریابید."},{"v":20,"t":"«و چون بینید که اورشلیم به لشکرهامحاصره شده است آنگاه بدانید که خرابی آن رسیده است."},{"v":21,"t":"آنگاه هر‌که در یهودیه باشد، به کوهستان فرار کند و هر‌که در شهر باشد، بیرون رود و هر‌که در صحرا بود، داخل شهر نشود."},{"v":22,"t":"زیرا که همان است ایام انتقام، تا آنچه مکتوب است تمام شود."},{"v":23,"t":"لیکن وای بر آبستنان وشیردهندگان در آن ایام، زیرا تنگی سخت برروی زمین و غضب بر این قوم حادث خواهد شد."},{"v":24,"t":"و به دم شمشیر خواهند افتاد و در میان جمیع امت‌ها به اسیری خواهند رفت و اورشلیم پایمال امت‌ها خواهد شد تا زمانهای امت‌ها به انجام رسد."},{"v":25,"t":"و در آفتاب و ماه و ستارگان علامات خواهد بود و بر زمین تنگی و حیرت از برای امت‌ها روی خواهد نمود به‌سبب شوریدن دریا وامواجش."},{"v":26,"t":"و دلهای مردم ضعف خواهد کرد از خوف و انتظار آن وقایعی که برربع مسکون ظاهرمی شود، زیرا قوات آسمان متزلزل خواهد شد."},{"v":27,"t":"و آنگاه پسر انسان را خواهند دید که بر ابری سوار شده با قوت و جلال عظیم می‌آید."},{"v":28,"t":"«و چون ابتدای این چیزها بشود راست شده، سرهای خود را بلند کنید از آن جهت که خلاصی شما نزدیک است.»"},{"v":29,"t":"و برای ایشان مثلی گفت که «درخت انجیر و سایر درختان راملاحظه نمایید،"},{"v":30,"t":"که چون می‌بینید شکوفه می‌کند خود می‌دانید که تابستان نزدیک است."},{"v":31,"t":"و همچنین شما نیز چون بینید که این امور واقع می‌شود، بدانید که ملکوت خدا نزدیک شده است."},{"v":32,"t":"هرآینه به شما می‌گویم که تا جمیع این امور واقع نشود، این فرقه نخواهد گذشت."},{"v":33,"t":"آسمان و زمین زایل می‌شود لیکن سخنان من زایل نخواهد شد."},{"v":34,"t":"پس خود را حفظ کنید مبادا دلهای شما ازپرخوری و مستی و اندیشه های دنیوی، سنگین گردد و آن روز ناگهان بر شما آید."},{"v":35,"t":"زیرا که مثل دامی بر جمیع سکنه تمام روی زمین خواهد آمد."},{"v":36,"t":"پس در هر وقت دعا کرده، بیدار باشید تاشایسته آن شوید که از جمیع این چیزهایی که به وقوع خواهد پیوست نجات یابید و در حضورپسر انسان بایستید.»"},{"v":37,"t":"و روزها را در هیکل تعلیم می‌داد و شبها بیرون رفته، در کوه معروف به زیتون به‌سر می‌برد."},{"v":38,"t":"و هر بامداد قوم نزد وی در هیکل می‌شتافتند تا کلام او را بشنوند."}]},"22":{"fa":[{"v":1,"t":"و چون عید فطیر که به فصح معروف است نزدیک شد،"},{"v":2,"t":"روسای کهنه وکاتبان مترصد می‌بودند که چگونه او را به قتل رسانند، زیرا که از قوم ترسیدند."},{"v":3,"t":"اما شیطان در یهودای مسمی به اسخریوطی که از‌جمله آن دوازده بود داخل گشت،"},{"v":4,"t":"و اورفته با روسای کهنه و سرداران سپاه گفتگو کرد که چگونه او را به ایشان تسلیم کند."},{"v":5,"t":"ایشان شادشده با او عهد بستند که نقدی به وی دهند."},{"v":6,"t":"و اوقبول کرده در صدد فرصتی برآمد که اورا درنهانی از مردم به ایشان تسلیم کند."},{"v":7,"t":"اما چون روز فطیر که در آن می‌بایست فصح را ذبح کنند رسید،"},{"v":8,"t":"پطرس و یوحنا را فرستاده، گفت: «بروید و فصح را بجهت ما آماده کنید تابخوریم.»"},{"v":9,"t":"به وی گفتند: «در کجا می‌خواهی مهیا کنیم؟»"},{"v":10,"t":"ایشان را گفت: «اینک هنگامی که داخل شهر شوید، شخصی با سبوی آب به شمابرمی خورد. به خانه‌ای که او درآید، از عقب وی بروید،"},{"v":11,"t":"و به صاحب‌خانه گویید، استاد تو را می گوید مهمانخانه کجا است تا در آن فصح را باشاگردان خود بخورم."},{"v":12,"t":"او بالاخانه‌ای بزرگ ومفروش به شما نشان خواهد داد در آنجا مهیاسازید.»"},{"v":13,"t":"پس رفته چنانکه به ایشان گفته بودیافتند و فصح را آماده کردند."},{"v":14,"t":"و چون وقت رسید با دوازده رسول بنشست."},{"v":15,"t":"و به ایشان گفت: «اشتیاق بی‌نهایت داشتم که پیش از زحمت دیدنم، این فصح را باشما بخورم."},{"v":16,"t":"زیرا به شما می‌گویم از این دیگرنمی خورم تا وقتی که در ملکوت خدا تمام شود.»"},{"v":17,"t":"پس پیاله‌ای گرفته، شکر نمود و گفت: «این رابگیرید و در میان خود تقسیم کنید."},{"v":18,"t":"زیرا به شما می‌گویم که تا ملکوت خدا نیاید، از میوه مودیگر نخواهم نوشید.»"},{"v":19,"t":"و نان را گرفته، شکرنمود و پاره کرده، به ایشان داد و گفت: «این است جسد من که برای شما داده می‌شود، این را به یادمن به‌جا آرید.»"},{"v":20,"t":"و همچنین بعد از شام پیاله راگرفت و گفت: «این پیاله عهد جدید است در خون من که برای شما ریخته می‌شود."},{"v":21,"t":"لیکن اینک دست آن کسی‌که مرا تسلیم می‌کند با من در سفره است."},{"v":22,"t":"زیرا که پسر انسان برحسب آنچه مقدراست، می‌رود لیکن وای بر آن کسی‌که او را تسلیم کند.»"},{"v":23,"t":"آنگاه از یکدیگر شروع کردند به پرسیدن که کدام‌یک از ایشان باشد که این کار بکند؟"},{"v":24,"t":"و در میان ایشان نزاعی نیز افتاد که کدام‌یک ازایشان بزرگتر می‌باشد؟"},{"v":25,"t":"آنگاه به ایشان گفت: «سلاطین امت‌ها بر ایشان سروری می‌کنند وحکام خود را ولی‌نعمت می‌خوانند."},{"v":26,"t":"لیکن شماچنین مباشید، بلکه بزرگتر از شما مثل کوچکترباشد و پیشوا چون خادم."},{"v":27,"t":"زیرا کدام‌یک بزرگتراست آنکه به غذا نشیند یا آنکه خدمت کند آیانیست آنکه نشسته است؟ لیکن من در میان شماچون خادم هستم."},{"v":28,"t":"و شما کسانی می‌باشید که در امتحانهای من با من به‌سر بردید."},{"v":29,"t":"و من ملکوتی برای شما قرار می‌دهم چنانکه پدرم برای من مقرر فرمود."},{"v":30,"t":"تا در ملکوت من از خوان من بخورید و بنوشید و بر کرسیها نشسته بردوازده سبط اسرائیل داوری کنید.»"},{"v":31,"t":"پس خداوند گفت: «ای شمعون، ای شمعون، اینک شیطان خواست شما را چون گندم غربال کند،"},{"v":32,"t":"لیکن من برای تو دعا کردم تاایمانت تلف نشود و هنگامی که تو بازگشت کنی برادران خود را استوار نما.»"},{"v":33,"t":"به وی گفت: «ای خداوند حاضرم که با تو بروم حتی در زندان و درموت.»"},{"v":34,"t":"گفت: «تو را می‌گویم‌ای پطرس امروزخروس بانگ نزده باشد که سه مرتبه انکار خواهی کرد که مرا نمی شناسی.»"},{"v":35,"t":"و به ایشان گفت: «هنگامی که شما را بی‌کیسه و توشه‌دان و کفش فرستادم به هیچ‌چیز محتاج شدید؟» گفتند هیچ."},{"v":36,"t":"پس به ایشان گفت: «لیکن الان هر‌که کیسه دارد، آن را بردارد و همچنین توشه‌دان را و کسی‌که شمشیر ندارد جامه خود را فروخته آن رابخرد."},{"v":37,"t":"زیرا به شما می‌گویم که این نوشته در من می‌باید به انجام رسید، یعنی با گناهکاران محسوب شد زیرا هر‌چه در خصوص من است، انقضا دارد."},{"v":38,"t":"گفتند: «ای خداوند اینک دوشمشیر.» به ایشان گفت: «کافی است.»"},{"v":39,"t":"و برحسب عادت بیرون شده به کوه زیتون رفت و شاگردانش از عقب او رفتند."},{"v":40,"t":"و چون به آن موضع رسید، به ایشان گفت: «دعا کنید تا درامتحان نیفتید.»"},{"v":41,"t":"و او از ایشان به مسافت پرتاپ سنگی دور شده، به زانو درآمد و دعا کرده، گفت:"},{"v":42,"t":"«ای پدر اگر بخواهی این پیاله را از من بگردان، لیکن نه به خواهش من بلکه به اراده تو.»"},{"v":43,"t":"وفرشته‌ای از آسمان بر او ظاهر شده او را تقویت می‌نمود."},{"v":44,"t":"پس به مجاهده افتاده به سعی بلیغتردعا کرد، چنانکه عرق او مثل قطرات خون بود که بر زمین می‌ریخت."},{"v":45,"t":"پس از دعا برخاسته نزدشاگردان خود آمده ایشان را از حزن در خواب یافت."},{"v":46,"t":"به ایشان گفت: «برای چه در خواب هستید؟ برخاسته دعا کنید تا در امتحان نیفتید.»"},{"v":47,"t":"و سخن هنوز بر زبانش بود که ناگاه جمعی آمدند و یکی از آن دوازده که یهودا نام داشت بردیگران سبقت جسته نزد عیسی آمد تا او راببوسد."},{"v":48,"t":"و عیسی بدو گفت: «ای یهودا آیا به بوسه پسر انسان را تسلیم می‌کنی؟»"},{"v":49,"t":"رفقایش چون دیدند که چه می‌شود عرض کردند خداوندابه شمشیر بزنیم."},{"v":50,"t":"و یکی از ایشان، غلام رئیس کهنه را زده، گوش راست او را از تن جدا کرد."},{"v":51,"t":"عیسی متوجه شده گفت: «تا به این بگذارید.» وگوش او را لمس نموده، شفا داد."},{"v":52,"t":"پس عیسی به روسای کهنه و سرداران سپاه هیکل و مشایخی که نزد او آمده بودند گفت: «گویا بر دزد با شمشیرها و چوبها بیرون آمدید."},{"v":53,"t":"وقتی که هر روزه در هیکل با شما می‌بودم دست بر من دراز نکردید، لیکن این است ساعت شما و قدرت ظلمت.»"},{"v":54,"t":"پس او را گرفته بردند و به‌سرای رئیس کهنه آوردند و پطرس از دور از عقب می‌آمد."},{"v":55,"t":"و چون در میان ایوان آتش افروخته گردش نشسته بودند، پطرس در میان ایشان بنشست."},{"v":56,"t":"آنگاه کنیزکی چون او را در روشنی آتش نشسته دید بر او چشم دوخته گفت: «این شخص هم با او می‌بود.»"},{"v":57,"t":"او وی را انکار کرده گفت: «ای زن او را نمی شناسم.»"},{"v":58,"t":"بعد از زمانی دیگری او را دیده گفت: «تو از اینها هستی.» پطرس گفت: «ای مرد، من نیستم.»"},{"v":59,"t":"و چون تخمین یک ساعت گذشت یکی دیگر با تاکیدگفت: «بلاشک این شخص از رفقای او است زیراکه جلیلی هم هست.»"},{"v":60,"t":"پطرس گفت: «ای مردنمی دانم چه می‌گویی؟» در همان ساعت که این رامی گفت خروس بانگ زد."},{"v":61,"t":"آنگاه خداوندروگردانیده به پطرس نظر افکند پس پطرس آن کلامی را که خداوند به وی گفته بود به‌خاطرآورد که قبل از بانگ زدن خروس سه مرتبه مراانکار خواهی کرد."},{"v":62,"t":"پس پطرس بیرون رفته زارزار بگریست."},{"v":63,"t":"و کسانی که عیسی را گرفته بودند، او راتازیانه زده استهزا نمودند."},{"v":64,"t":"و چشم او را بسته طپانچه بر رویش زدند و از وی سوال کرده، گفتند: «نبوت کن که تو را زده است؟»"},{"v":65,"t":"و بسیارکفر دیگر به وی گفتند."},{"v":66,"t":"و چون روز شد اهل شورای قوم یعنی روسای کهنه و کاتبان فراهم آمده در مجلس خوداو را آورده،"},{"v":67,"t":"گفتند: «اگر تو مسیح هستی به مابگو: «او به ایشان گفت: «اگر به شما گویم مراتصدیق نخواهید کرد."},{"v":68,"t":"و اگر از شما سوال کنم جواب نمی دهید و مرا رها نمی کنید."},{"v":69,"t":"لیکن بعداز این پسر انسان به طرف راست قوت خداخواهد نشست.»"},{"v":70,"t":"همه گفتند: «پس تو پسر خداهستی؟» او به ایشان گفت: «شما می‌گویید که من هستم.»"},{"v":71,"t":"گفتند: «دیگر ما را چه حاجت به شهادت است، زیرا خود از زبانش شنیدیم.»"}]},"23":{"fa":[{"v":1,"t":"پس تمام جماعت ایشان برخاسته، اورا نزد پیلاطس بردند."},{"v":2,"t":"و شکایت بر اوآغاز نموده، گفتند: «این شخص را یافته‌ایم که قوم را گمراه می‌کند و از جزیه دادن به قیصر منع می‌نماید و می‌گوید که خود مسیح و پادشاه است.»"},{"v":3,"t":"پس پیلاطس از او پرسیده، گفت: «آیا توپادشاه یهود هستی؟» او در جواب وی گفت: «تومی گویی.»"},{"v":4,"t":"آنگاه پیلاطس به روسای کهنه وجمیع قوم گفت که «در این شخص هیچ عیبی نمی یابم.»"},{"v":5,"t":"ایشان شدت نموده گفتند که «قوم رامی شوراند و در تمام یهودیه از جلیل گرفته تا به اینجا تعلیم می‌دهد.»"},{"v":6,"t":"چون پیلاطس نام جلیل را شنید پرسید که «آیا این مرد جلیلی است؟»"},{"v":7,"t":"و چون مطلع شد که از ولایت هیرودیس است او را نزد وی فرستاد، چونکه هیرودیس در آن ایام در اورشلیم بود."},{"v":8,"t":"اما هیرودیس چون عیسی را دید، بغایت شادگردید زیرا که مدت مدیدی بود می‌خو. است اورا ببیند چونکه شهرت او را بسیار شنیده بود ومترصد می‌بود که معجزه‌ای از او بیند."},{"v":9,"t":"پس چیزهای بسیار از وی پرسید لیکن او به وی هیچ جواب نداد."},{"v":10,"t":"و روسای کهنه و کاتبان حاضرشده به شدت تمام بر وی شکایت می‌نمودند."},{"v":11,"t":"پس هیرودیس با لشکریان خود او را افتضاح نموده و استهزا کرده لباس فاخر بر او پوشانید ونزد پیلاطس او را باز فرستاد."},{"v":12,"t":"و در همان روزپیلاطس و هیرودیس با یکدیگر مصالحه کردند، زیرا قبل از آن در میانشان عداوتی بود."},{"v":13,"t":"پس پیلاطس روسای کهنه و سرادران وقوم را خوانده،"},{"v":14,"t":"به ایشان گفت: «این مرد را نزدمن آوردید که قوم را می‌شوراند. الحال من او رادر حضور شما امتحان کردم و از آنچه بر او ادعامی کنید اثری نیافتم."},{"v":15,"t":"و نه هیرودیس هم زیراکه شما را نزد او فرستادم و اینک هیچ عمل مستوجب قتل از او صادر نشده است."},{"v":16,"t":"پس اورا تنبیه نموده رها خواهم کرد.»"},{"v":17,"t":"زیرا او را لازم بود که هر عیدی کسی را برای ایشان آزاد کند."},{"v":18,"t":"آنگاه همه فریاد کرده، گفتند: «او را هلاک کن وبرابا را برای ما رها فرما.»"},{"v":19,"t":"و او شخصی بود که به‌سبب شورش و قتلی که در شهر واقع شده بود، در زندان افکنده شده بود."},{"v":20,"t":"باز پیلاطس نداکرده خواست که عیسی را رها کند."},{"v":21,"t":"لیکن ایشان فریاد زده گفتند: «او را مصلوب کن، مصلوب کن.»"},{"v":22,"t":"بار سوم به ایشان گفت: «چرا؟ چه بدی کرده است؟ من در او هیچ علت قتل نیافتم. پس او را تادیب کرده رها می‌کنم.»"},{"v":23,"t":"اماایشان به صداهای بلند مبالغه نموده خواستند که مصلوب شود و آوازهای ایشان و روسای کهنه غالب آمد."},{"v":24,"t":"پس پیلاطس فرمود که برحسب خواهش ایشان بشود."},{"v":25,"t":"و آن کس را که به‌سبب شورش و قتل در زندان حبس بود که خواستند رها کرد و عیسی را به خواهش ایشان سپرد."},{"v":26,"t":"و چون او را می‌بردند شمعون قیروانی را که از صحرا می‌آمد مجبور ساخته صلیب را بر اوگذاردند تا از عقب عیسی ببرد."},{"v":27,"t":"و گروهی بسیاراز قوم و زنانی که سینه می‌زدند و برای او ماتم می‌گرفتند، در عقب او افتادند."},{"v":28,"t":"آنگاه عیسی به سوی آن زنان روی گردانیده، گفت: «ای دختران اورشلیم برای من گریه مکنید، بلکه بجهت خود واولاد خود ماتم کنید."},{"v":29,"t":"زیرا اینک ایامی می‌آیدکه در آنها خواهند گفت، خوشابحال نازادگان ورحمهایی که بار نیاوردند و پستانهایی که شیرندادند."},{"v":30,"t":"و در آن هنگام به کوهها خواهند گفت که بر ما بیفتید و به تلها که ما را پنهان کنید."},{"v":31,"t":"زیرااگر این کارها را به چوب تر کردند به چوب خشک چه خواهد شد؟»"},{"v":32,"t":"و دو نفر دیگر را که خطاکار بودند نیزآوردند تا ایشان را با او بکشند."},{"v":33,"t":"و چون به موضعی که آن را کاسه سر می‌گویند رسیدند، اورا در آنجا با آن دو خطاکار، یکی بر طرف راست و دیگری بر چپ او مصلوب کردند."},{"v":34,"t":"عیسی گفت: «ای پدر اینها را بیامرز، زیراکه نمی دانند چه می‌کنند.» پس جامه های او راتقسیم کردند و قرعه افکندند."},{"v":35,"t":"و گروهی به تماشا ایستاده بودند. و بزرگان نیز تمسخرکنان با ایشان می‌گفتند: «دیگران را نجات داد. پس اگر او مسیح و برگزیده خدا می‌باشد خود رابرهاند.»"},{"v":36,"t":"و سپاهیان نیز او را استهزا می‌کردند و آمده او را سرکه می‌دادند،"},{"v":37,"t":"و می‌گفتند: «اگر توپادشاه یهود هستی خود را نجات ده.»"},{"v":38,"t":"و بر سراو تقصیرنامه‌ای نوشتند به خط یونانی و رومی وعبرانی که «این است پادشاه یهود.»"},{"v":39,"t":"و یکی از آن دو خطاکار مصلوب بر وی کفر گفت که «اگر تو مسیح هستی خود را و ما رابرهان.»"},{"v":40,"t":"اما آن دیگری جواب داده، او را نهیب کرد و گفت: «مگر تو از خدا نمی ترسی؟ چونکه تو نیز زیر همین حکمی."},{"v":41,"t":"و اما ما به انصاف، چونکه جزای اعمال خود را یافته‌ایم، لیکن این شخص هیچ کار بی‌جا نکرده است.»"},{"v":42,"t":"پس به عیسی گفت: «ای خداوند، مرا به یاد آور هنگامی که به ملکوت خود آیی.»"},{"v":43,"t":"عیسی به وی گفت: «هرآینه به تو می‌گویم امروز با من در فردوس خواهی بود.»"},{"v":44,"t":"و تخمین از ساعت ششم تا ساعت نهم، ظلمت تمام روی زمین را فرو گرفت."},{"v":45,"t":"وخورشید تاریک گشت و پرده قدس از میان بشکافت."},{"v":46,"t":"و عیسی به آواز بلند صدا زده گفت: «ای پدر به‌دستهای تو روح خود را می‌سپارم.» این را بگفت و جان را تسلیم نمود."},{"v":47,"t":"امایوزباشی چون این ماجرا را دید، خدا را تمجیدکرده، گفت: «در حقیقت، این مرد صالح بود.»"},{"v":48,"t":"وتمامی گروه که برای این تماشا جمع شده بودندچون این وقایع را دیدند، سینه زنان برگشتند."},{"v":49,"t":"و جمیع آشنایان او از دور ایستاده بودند، با زنانی که از جلیل او را متابعت کرده بودند تا این امور راببینند."},{"v":50,"t":"و اینک یوسف نامی از اهل شورا که مردنیکو و صالح بود،"},{"v":51,"t":"که در رای و عمل ایشان مشارکت نداشت و از اهل رامه بلدی از بلاد یهودبود و انتظار ملکوت خدا را می‌کشید،"},{"v":52,"t":"نزدیک پیلاطس آمده جسد عیسی را طلب نمود."},{"v":53,"t":"پس آن را پایین آورده در کتان پیچید و در قبری که ازسنگ تراشیده بود و هیچ‌کس ابد در آن دفن نشده بود سپرد."},{"v":54,"t":"و آن روز تهیه بود و سبت نزدیک می‌شد."},{"v":55,"t":"و زنانی که در عقب او از جلیل آمده بودند از پی او رفتند و قبر و چگونگی گذاشته شدن بدن او را دیدند."},{"v":56,"t":"پس برگشته، حنوط و عطریات مهیا ساختند و روز سبت را به حسب حکم آرام گرفتند."}]},"24":{"fa":[{"v":1,"t":"پس در روز اول هفته هنگام سپیده صبح، حنوطی را که درست کرده بودندبا خود برداشته به‌سر قبر‌آمدند و بعضی دیگران همراه ایشان."},{"v":2,"t":"و سنگ را از سر قبر غلطانیده دیدند."},{"v":3,"t":"چون داخل شدند، جسد خداوند عیسی را نیافتند"},{"v":4,"t":"و واقع شد هنگامی که ایشان از این امر متحیر بودند که ناگاه دو مرد در لباس درخشنده نزد ایشان بایستادند."},{"v":5,"t":"و چون ترسان شده سرهای خود را به سوی زمین افکنده بودند، به ایشان گفتند: «چرا زنده را از میان مردگان می‌طلبید؟"},{"v":6,"t":"در اینجا نیست، بلکه برخاسته است. به یاد آورید که چگونه وقتی که در جلیل بود شمارا خبر داده،"},{"v":7,"t":"گفت ضروری است که پسر انسان به‌دست مردم گناهکار تسلیم شده مصلوب گرددو روز سوم برخیزد.»"},{"v":8,"t":"پس سخنان او را به‌خاطرآوردند."},{"v":9,"t":"و از سر قبر برگشته، آن یازده و دیگران را ازهمه این امور مطلع ساختند."},{"v":10,"t":"و مریم مجدلیه ویونا و مریم مادر یعقوب و دیگر رفقای ایشان بودند که رسولان را از این چیزها مطلع ساختند."},{"v":11,"t":"لیکن سخنان زنان را هذیان پنداشته باورنکردند."},{"v":12,"t":"اما پطرس برخاسته، دوان دوان به سوی قبر رفت و خم شده کفن را تنها گذاشته دیدو از این ماجرا در عجب شده به خانه خود رفت."},{"v":13,"t":"و اینک در همان روز دو نفر از ایشان می‌رفتند به سوی قریه‌ای که از اورشلیم به مسافت، شصت تیر پرتاب دور بود و عمواس نام داشت."},{"v":14,"t":"و با یک دیگر از تمام این وقایع گفتگومی کردند."},{"v":15,"t":"و چون ایشان در مکالمه و مباحثه می‌بودند، ناگاه خود عیسی نزدیک شده، با ایشان همراه شد."},{"v":16,"t":"ولی چشمان ایشان بسته شد تا اورا نشناسند."},{"v":17,"t":"او به ایشان گفت: «چه حرفها است که با یکدیگر می‌زنید و راه را به کدورت می‌پیمایید؟»"},{"v":18,"t":"یکی که کلیوپاس نام داشت درجواب وی گفت: «مگر تو در اورشلیم غریب وتنها هستی و از آنچه در این ایام در اینجا واقع شدواقف نیستی؟»"},{"v":19,"t":"به ایشان گفت: «چه چیزاست؟» گفتندش: «درباره عیسی ناصری که مردی بود نبی و قادر در فعل و قول در حضورخدا و تمام قوم،"},{"v":20,"t":"و چگونه روسای کهنه وحکام ما او را به فتوای قتل سپردند و او رامصلوب ساختند."},{"v":21,"t":"اما ما امیدوار بودیم که همین است آنکه می‌باید اسرائیل را نجات دهد وعلاوه بر این همه، امروز از وقوع این امور روزسوم است،"},{"v":22,"t":"و بعضی از زنان ما هم ما را به حیرت انداختند که بامدادان نزد قبر رفتند،"},{"v":23,"t":"وجسد او را نیافته آمدند و گفتند که فرشتگان را دررویا دیدیم که گفتند او زنده شده است."},{"v":24,"t":"وجمعی از رفقای ما به‌سر قبر رفته، آن چنانکه زنان گفته بودند یافتند لیکن او را ندیدند.»"},{"v":25,"t":"او به ایشان گفت: «ای بی‌فهمان وسست دلان از ایمان آوردن به انچه انبیا گفته‌اند."},{"v":26,"t":"آیا نمی بایست که مسیح این زحمات را بیند تابه جلال خود برسد؟»"},{"v":27,"t":"پس از موسی و سایرانبیا شروع کرده، اخبار خود را در تمام کتب برای ایشان شرح فرمود."},{"v":28,"t":"و چون به آن دهی که عازم آن بودندرسیدند، او قصد نمود که دورتر رود."},{"v":29,"t":"و ایشان الحاح کرده، گفتند که «با ما باش. چونکه شب نزدیک است و روز به آخر رسیده.» پس داخل گشته با ایشان توقف نمود."},{"v":30,"t":"و چون با ایشان نشسته بود نان را گرفته برکت داد و پاره کرده به ایشان داد."},{"v":31,"t":"که ناگاه چشمانشان باز شده، او راشناختند و در ساعت از ایشان غایب شد."},{"v":32,"t":"پس با یکدیگر گفتند: «آیا دل در درون مانمی سوخت، وقتی که در راه با ما تکلم می‌نمود وکتب را بجهت ما تفسیر می‌کرد؟»"},{"v":33,"t":"و در آن ساعت برخاسته به اورشلیم مراجعت کردند و آن یازده را یافتند که با رفقای خود جمع شده"},{"v":34,"t":"می گفتند: «خداوند در حقیقت برخاسته و به شمعون ظاهر شده است.»"},{"v":35,"t":"و آن دو نفر نیز ازسرگذشت راه و کیفیت شناختن او هنگام پاره کردن نان خبر دادند."},{"v":36,"t":"و ایشان در این گفتگو می‌بودند که ناگاه عیسی خود در میان ایشان ایستاده، به ایشان گفت: «سلام بر شما باد.»"},{"v":37,"t":"اما ایشان لرزان وترسان شده گمان بردند که روحی می‌بینند."},{"v":38,"t":"به ایشان گفت: «چرا مضطرب شدید و برای چه دردلهای شما شبهات روی می‌دهد؟"},{"v":39,"t":"دستها وپایهایم را ملاحظه کنید که من خود هستم و دست بر من گذارده ببینید، زیرا که روح گوشت واستخوان ندارد، چنانکه می‌نگرید که در من است.»"},{"v":40,"t":"این را گفت و دستها و پایهای خود رابدیشان نشان داد."},{"v":41,"t":"و چون ایشان هنوز ازخوشی تصدیق نکرده، در عجب مانده بودند، به ایشان گفت: «چیز خوراکی در اینجا دارید؟»"},{"v":42,"t":"پس قدری از ماهی بریان و از شانه عسل به وی دادند."},{"v":43,"t":"پس آن را گرفته پیش ایشان بخورد."},{"v":44,"t":"و به ایشان گفت: «همین است سخنانی که وقتی با شما بودم گفتم ضروری است که آنچه درتورات موسی و صحف انبیا و زبور درباره من مکتوب است به انجام رسد.»"},{"v":45,"t":"و در آن وقت ذهن ایشان را روشن کرد تا کتب را بفهمند."},{"v":46,"t":"و به ایشان گفت: «بر همین منوال مکتوب است وبدینطور سزاوار بود که مسیح زحمت کشد و روزسوم از مردگان برخیزد."},{"v":47,"t":"و از اورشلیم شروع کرده، موعظه به توبه و آمرزش گناهان در همه امت‌ها به نام او کرده شود."},{"v":48,"t":"و شما شاهد بر این امور هستید."},{"v":49,"t":"و اینک، من موعود پدر خود را برشما می‌فرستم. پس شما در شهر اورشلیم بمانیدتا وقتی که به قوت از اعلی آراسته شوید.»"},{"v":50,"t":"پس ایشان را بیرون از شهر تا بیت عنیا بردو دستهای خود را بلند کرده، ایشان را برکت داد."},{"v":51,"t":"و چنین شد که در حین برکت دادن ایشان، ازایشان جدا گشته، به سوی آسمان بالا برده شد."},{"v":52,"t":"پس او را پرستش کرده، با خوشی عظیم به سوی اورشلیم برگشتند."},{"v":53,"t":"و پیوسته درهیکل مانده، خدا را حمد و سپاس می‌گفتند. آمین."}]}});
